import React, { useMemo } from 'react';
import { Ticket, TicketStatus, TicketPriority, User } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Activity, CheckCircle, Clock, Plus, TrendingUp, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  tickets: Ticket[];
  currentUser: User;
  onCreateTicket: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ tickets, currentUser, onCreateTicket }) => {

  const stats = useMemo(() => {
    const total = tickets.length;
    const open = tickets.filter(t => t.status === TicketStatus.OPEN).length;
    const resolved = tickets.filter(t => t.status === TicketStatus.RESOLVED).length;
    // Críticos ativos (Críticos que não estão resolvidos)
    const criticalActive = tickets.filter(t => 
        t.priority === TicketPriority.CRITICAL && 
        t.status !== TicketStatus.RESOLVED
    ).length;

    const resolutionRate = total > 0 ? Math.round((resolved / total) * 100) : 0;

    return {
      total,
      open,
      resolved,
      criticalActive,
      resolutionRate
    };
  }, [tickets]);

  const chartData = useMemo(() => {
      const data: any[] = [];
      const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

      const now = new Date();
      // Mostra os últimos 12 meses para preencher bem a tela
      for (let i = 11; i >= 0; i--) {
          const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
          data.push({
              name: `${months[d.getMonth()]}`,
              Abertos: 0,
              Resolvidos: 0,
              monthIndex: d.getMonth(),
              year: d.getFullYear()
          });
      }

      tickets.forEach(t => {
          const d = t.createdAt;
          const item = data.find(i => i.monthIndex === d.getMonth() && i.year === d.getFullYear());
          if (item) {
              item.Abertos += 1;
              if (t.status === TicketStatus.RESOLVED) {
                  item.Resolvidos += 1;
              }
          }
      });

      return data;
  }, [tickets]);

  return (
    <div className="space-y-6">

      {/* Top Action Row matches the image's "Novo Chamado" button position */}
      <div className="flex justify-end">
          <button 
            onClick={onCreateTicket}
            className="flex items-center space-x-2 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors font-medium shadow-sm"
          >
              <Plus size={18} />
              <span>Novo Chamado</span>
          </button>
      </div>

      {/* Welcome Card */}
      <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm flex flex-col md:flex-row items-center justify-between gap-6">
          <div>
              <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                  Olá, {currentUser.name.split(' ')[0]}! <span className="text-2xl">👋</span>
              </h1>
              <p className="text-gray-500 mt-1">Visão geral do desempenho do suporte técnico e métricas.</p>
          </div>

          <div className="bg-primary-50 rounded-lg p-4 flex items-center gap-4 min-w-[200px] border border-primary-100">
              <div className="p-2 bg-primary-100 rounded-lg text-primary-600">
                  <TrendingUp size={24} />
              </div>
              <div>
                  <p className="text-xs font-bold text-primary-800 uppercase tracking-wide">TAXA DE RESOLUÇÃO</p>
                  <p className="text-2xl font-bold text-gray-900">{stats.resolutionRate}%</p>
              </div>
          </div>
      </div>

      {/* KPI Cards Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Total */}
        <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-500">Total de Chamados</p>
                <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.total}</h3>
            </div>
            <div className="h-10 w-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center">
                <Activity size={20} />
            </div>
        </div>

        {/* Abertos */}
        <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-500">Chamados Abertos</p>
                <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.open}</h3>
            </div>
            <div className="h-10 w-10 rounded-full bg-yellow-50 text-yellow-600 flex items-center justify-center">
                <Clock size={20} />
            </div>
        </div>

        {/* Resolvidos */}
        <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-500">Resolvidos</p>
                <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.resolved}</h3>
            </div>
            <div className="h-10 w-10 rounded-full bg-green-50 text-green-600 flex items-center justify-center">
                <CheckCircle size={20} />
            </div>
        </div>

        {/* Críticos Ativos */}
        <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-500">Críticos Ativos</p>
                <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.criticalActive}</h3>
            </div>
            <div className="h-10 w-10 rounded-full bg-red-50 text-red-600 flex items-center justify-center">
                <AlertTriangle size={20} />
            </div>
        </div>
      </div>

      {/* Full Width Chart */}
      <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-base font-bold text-gray-900">Evolução Mensal: Abertos vs Resolvidos</h3>
                <div className="flex gap-4">
                    <div className="flex items-center text-xs text-gray-500">
                        <span className="w-3 h-3 rounded-full bg-primary-500 mr-2"></span> Abertos
                    </div>
                    <div className="flex items-center text-xs text-gray-500">
                        <span className="w-3 h-3 rounded-full bg-green-500 mr-2"></span> Resolvidos
                    </div>
                </div>
            </div>
            <div className="h-[350px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }} barGap={8}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                        <XAxis 
                            dataKey="name" 
                            axisLine={false} 
                            tickLine={false} 
                            tick={{ fill: '#9ca3af', fontSize: 12 }} 
                            dy={10}
                        />
                        <YAxis 
                            axisLine={false} 
                            tickLine={false} 
                            tick={{ fill: '#9ca3af', fontSize: 12 }} 
                        />
                        <Tooltip 
                            cursor={{ fill: '#f9fafb' }}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        />
                        <Bar dataKey="Abertos" fill="#e11d48" radius={[4, 4, 0, 0]} maxBarSize={40} />
                        <Bar dataKey="Resolvidos" fill="#10b981" radius={[4, 4, 0, 0]} maxBarSize={40} />
                    </BarChart>
                </ResponsiveContainer>
            </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { TicketDetail } from './components/TicketDetail';
import { Login } from './components/Login';
import { UserManagement } from './components/UserManagement';
import { Notifications } from './components/Notifications';
import { Dashboard } from './components/Dashboard';
import { Ticket, ViewState, TicketStatus, User } from './types';
import { supabase } from './services/supabase';
import { Loader2, Menu } from 'lucide-react';
import { Logo } from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [ticketToEdit, setTicketToEdit] = useState<Ticket | null>(null);
  const [loading, setLoading] = useState(true);

  // Mobile Sidebar State
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Check auth session on load
  useEffect(() => {
    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            fetchProfile(session.user.id, session.user.email!);
        } else {
            setCurrentUser(null);
            setTickets([]);
            setLoading(false);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch tickets whenever user changes or view updates
  useEffect(() => {
      if (currentUser) {
          fetchTickets();
      }
  }, [currentUser, currentView]);

  const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
          await fetchProfile(session.user.id, session.user.email!);
      } else {
          setLoading(false);
      }
  };

  const fetchProfile = async (userId: string, email: string) => {
      try {
          // 1. Get Auth Metadata to ensure we have the real name entered during sign up
          const { data: authUser } = await supabase.auth.getUser();
          const metaName = authUser.user?.user_metadata?.full_name;

          // Fallback name logic: Metadata > Email
          const displayName = metaName || email.split('@')[0];

          // 2. Attempt to fetch profile from DB
          let { data, error } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', userId)
            .maybeSingle();

          // 3. SELF-HEALING: If profile is missing but Auth exists, create it now.
          if (!data) {
            console.log("Profile missing for authenticated user. Creating default 'USER' profile...");

            const { data: newProfile, error: createError } = await supabase
                .from('profiles')
                .insert([{ 
                    id: userId, 
                    email: email, 
                    name: displayName, // Uses the real name from registration if available
                    role: 'USER', // Enforced default role
                    is_active: true
                }])
                .select()
                .single();

            if (createError) {
                console.error("Failed to auto-create profile:", createError);
                throw createError;
            }
            data = newProfile;
          } else if (error) {
            throw error;
          }

          // 4. Check for INACTIVE status
          if (data.is_active === false) {
              alert("Sua conta foi desativada pelo administrador. Entre em contato com o suporte.");
              await supabase.auth.signOut();
              setCurrentUser(null);
              setLoading(false);
              return;
          }

          // 5. SPECIAL ADMIN OVERRIDE (Bootstrap)
          const superAdmins = ['ti@grupoairslaid.com.br'];
          if (superAdmins.includes(email) || email.startsWith('admin') || email.startsWith('dev')) {
             if (data && data.role !== 'ADMIN') {
                 console.log(`Promoting super user ${email} to ADMIN...`);
                 await supabase.from('profiles').update({ role: 'ADMIN' }).eq('id', userId);
                 data.role = 'ADMIN';
             }
          }

          if (data) {
            setCurrentUser({
                id: data.id,
                name: data.name, // Use DB name (which we ensured matches metadata on creation)
                email: data.email || email,
                role: data.role,
                isActive: data.is_active
            });
          }
      } catch (error) {
          console.error('Error fetching/creating profile:', error);
      } finally {
          setLoading(false);
      }
  };

  const fetchTickets = async () => {
      try {
          // Alterado para fazer JOIN com a tabela profiles e pegar o nome atualizado
          const { data, error } = await supabase
            .from('tickets')
            .select('*, profiles:requester_id(name)')
            .order('created_at', { ascending: false });

          if (error) throw error;

          const formattedTickets: Ticket[] = data.map((t: any) => ({
              id: t.id,
              ticketNumber: t.ticket_number || 0,
              title: t.title,
              description: t.description,
              // Usa o nome do perfil (atualizado) se existir, senão usa o nome gravado no ticket (backup)
              requester: t.profiles?.name || t.requester_name,
              requesterId: t.requester_id,
              priority: t.priority,
              status: t.status,
              category: t.category,
              createdAt: new Date(t.created_at),
              updatedAt: t.updated_at ? new Date(t.updated_at) : new Date(t.created_at),
              resolvedAt: t.resolved_at ? new Date(t.resolved_at) : undefined,
              attachments: t.attachments || []
          }));

          setTickets(formattedTickets);
      } catch (error) {
          console.error('Error fetching tickets:', error);
      }
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      setCurrentView('DASHBOARD');
  };

  const handleCreateTicket = async (newTicketData: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => {
    if (!currentUser) return;

    try {
        if (ticketToEdit) {
            // Update existing ticket
            const { error } = await supabase
                .from('tickets')
                .update({
                    title: newTicketData.title,
                    description: newTicketData.description,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: newTicketData.status,
                    attachments: newTicketData.attachments
                })
                .eq('id', ticketToEdit.id);

            if (error) throw error;

            // Audit Log for Edit
            await supabase.from('audit_logs').insert({
                ticket_id: ticketToEdit.id,
                actor_id: currentUser.id,
                action: 'EDITED',
                details: 'Detalhes do chamado editados'
            });

            setTicketToEdit(null);
        } else {
            // Create new ticket
            // ticket_number is generated automatically by Postgres
            const { data: newTicket, error } = await supabase
                .from('tickets')
                .insert([{
                    title: newTicketData.title,
                    description: newTicketData.description,
                    requester_name: currentUser?.name, 
                    requester_id: currentUser?.id,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: 'OPEN',
                    attachments: newTicketData.attachments
                }])
                .select()
                .single();

            if (error) throw error;

            if (newTicket) {
                // Audit Log for Creation
                await supabase.from('audit_logs').insert({
                    ticket_id: newTicket.id,
                    actor_id: currentUser.id,
                    action: 'CREATED',
                    details: `Chamado criado com prioridade ${newTicketData.priority}`
                });

                // NOTIFICATION LOGIC: Notify all Admins
                const { data: admins } = await supabase.from('profiles').select('id').eq('role', 'ADMIN');
                if (admins && admins.length > 0) {
                    const notifications = admins.map(admin => ({
                        user_id: admin.id,
                        title: 'Novo Chamado Criado',
                        message: `${currentUser?.name} abriu um novo chamado: ${newTicketData.title}`,
                        ticket_id: newTicket.id
                    }));
                    await supabase.from('notifications').insert(notifications);
                }
            }
        }

        await fetchTickets(); // Refresh list

        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS'); // Return to list view after edit/create
        }
    } catch (error) {
        console.error("Error saving ticket:", error);
        alert("Falha ao salvar chamado. Por favor, tente novamente.");
    }
  };

  const handleSelectTicket = (ticket: Ticket) => {
    setSelectedTicket(ticket);
    setCurrentView('TICKET_DETAIL');
  };

  const handleSelectNotificationTicket = async (ticketId: string) => {
      // Find the ticket in the current list or fetch it
      const existing = tickets.find(t => t.id === ticketId);
      if (existing) {
          setSelectedTicket(existing);
          setCurrentView('TICKET_DETAIL');
      } else {
          // Fallback fetch if not loaded
          const { data } = await supabase.from('tickets').select('*, profiles:requester_id(name)').eq('id', ticketId).single();
          if (data) {
             const formatted: Ticket = {
                id: data.id,
                ticketNumber: data.ticket_number,
                title: data.title,
                description: data.description,
                requester: data.profiles?.name || data.requester_name,
                requesterId: data.requester_id,
                priority: data.priority,
                status: data.status,
                category: data.category,
                createdAt: new Date(data.created_at),
                updatedAt: data.updated_at ? new Date(data.updated_at) : new Date(data.created_at),
                resolvedAt: data.resolved_at ? new Date(data.resolved_at) : undefined,
                attachments: data.attachments || []
             };
             setSelectedTicket(formatted);
             setCurrentView('TICKET_DETAIL');
          }
      }
  };

  const handleDeleteTicket = async (id: string) => {
      try {
        const { error } = await supabase.from('tickets').delete().eq('id', id);
        if (error) throw error;

        setTickets(tickets.filter(t => t.id !== id));
        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS');
        }
      } catch (error) {
          console.error("Error deleting ticket:", error);
          alert("Falha ao excluir chamado.");
      }
  };

  const handleEditTicket = (ticket: Ticket) => {
      setTicketToEdit(ticket);
      setCurrentView('EDIT_TICKET');
  };

  const handleUpdateStatus = async (id: string, status: TicketStatus) => {
    if (!currentUser) return;

    try {
        // Prepare update data
        const updates: any = { status };

        // Logic for Resolved Date
        if (status === TicketStatus.RESOLVED) {
            updates.resolved_at = new Date().toISOString();
        } else {
            // If reopening, maybe clear resolved_at? 
            // updates.resolved_at = null; // Optional: Uncomment if reopening should clear the date
        }

        const { error } = await supabase
            .from('tickets')
            .update(updates)
            .eq('id', id);

        if (error) throw error;

        // Audit Log for Status Change
        await supabase.from('audit_logs').insert({
            ticket_id: id,
            actor_id: currentUser.id,
            action: 'STATUS_CHANGE',
            details: `Status alterado para ${status}`
        });

        // Update local state immediately (Optimistic or Fetch)
        setTickets(prev => prev.map(t => {
            if (t.id === id) {
                return {
                    ...t,
                    status,
                    resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : t.resolvedAt,
                    updatedAt: new Date() // Optimistic update for Last Update
                };
            }
            return t;
        }));

        if (selectedTicket && selectedTicket.id === id) {
            const updatedTicket = { 
                ...selectedTicket, 
                status,
                resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : selectedTicket.resolvedAt,
                updatedAt: new Date()
            };
            setSelectedTicket(updatedTicket);

            // NOTIFICATION LOGIC: Notify the requester if status changes
            // If I am an admin changing a user's ticket
            if (currentUser.role === 'ADMIN') {
                const { data: profile } = await supabase.from('profiles').select('name').eq('id', currentUser.id).single();
                const adminName = profile?.name || 'Admin';

                // Don't notify if I am the requester too
                if (selectedTicket.requesterId !== currentUser.id) {
                    await supabase.from('notifications').insert({
                        user_id: selectedTicket.requesterId,
                        title: 'Status Atualizado',
                        message: `Seu chamado "${selectedTicket.title}" mudou para ${status} por ${adminName}.`,
                        ticket_id: id
                    });
                }
            }
        }
    } catch (error) {
        console.error("Error updating status:", error);
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (currentView) {
      case 'CREATE_TICKET':
      case 'EDIT_TICKET':
        return (
          <TicketForm 
            onSave={handleCreateTicket} 
            onCancel={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} 
            initialData={currentView === 'EDIT_TICKET' ? ticketToEdit || undefined : undefined}
            currentUser={currentUser}
          />
        );
      case 'TICKET_DETAIL':
        return selectedTicket ? (
          <TicketDetail 
            ticket={selectedTicket}
            currentUser={currentUser}
            onBack={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')}
            onUpdateStatus={handleUpdateStatus}
            onDelete={handleDeleteTicket}
            onEdit={handleEditTicket}
          />
        ) : (
           <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
           />
        );
      case 'USERS':
        return currentUser.role === 'ADMIN' ? <UserManagement currentUser={currentUser} /> : <div>Acesso Negado</div>;
      case 'NOTIFICATIONS':
        return <Notifications currentUser={currentUser} onSelectNotification={handleSelectNotificationTicket} />;
      case 'MY_TICKETS':
      case 'ALL_TICKETS':
        return (
            <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
            />
        );
      case 'DASHBOARD':
      default:
        return <Dashboard tickets={tickets} currentUser={currentUser} onCreateTicket={() => setCurrentView('CREATE_TICKET')} />;
    }
  };

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <Loader2 className="animate-spin text-primary-600" size={48} />
          </div>
      );
  }

  if (!currentUser) {
    return <Login onLoginSuccess={() => checkUser()} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        currentUser={currentUser} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 w-full bg-white z-30 border-b border-gray-200 px-4 py-3 flex items-center justify-between">
          <div className="flex items-center space-x-3">
              <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="p-1 text-gray-600 hover:bg-gray-100 rounded-lg"
              >
                  <Menu size={24} />
              </button>
              <div className="flex items-center space-x-2">
                 <Logo className="h-8 w-auto" />
                 <span className="text-lg font-bold text-gray-800">AirService</span>
              </div>
          </div>
          <div className="h-8 w-8 rounded-full bg-primary-600 text-white flex items-center justify-center text-xs font-bold">
              {currentUser.name.charAt(0).toUpperCase()}
          </div>
      </div>

      <main className={`flex-1 p-4 md:p-8 overflow-y-auto h-screen transition-all duration-300 ${isSidebarOpen ? '' : 'ml-0'} md:ml-64 pt-20 md:pt-8`}>
        {/* Changed from max-w-6xl mx-auto to w-[95%] mx-auto to stretch the grid */}
        <div className="w-full md:w-[95%] mx-auto">
          <header className="mb-6 md:mb-8 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <h1 className="text-xl md:text-2xl font-bold text-gray-900">
                {currentView === 'DASHBOARD' && (currentUser.role === 'ADMIN' ? 'Visão Geral' : 'Dashboard')}
                {currentView === 'MY_TICKETS' && 'Meus Chamados'}
                {currentView === 'ALL_TICKETS' && 'Todos os Chamados'}
                {currentView === 'CREATE_TICKET' && 'Novo Chamado'}
                {currentView === 'EDIT_TICKET' && 'Editar Chamado'}
                {currentView === 'TICKET_DETAIL' && 'Detalhes do Chamado'}
                {currentView === 'USERS' && 'Gestão de Usuários'}
                {currentView === 'NOTIFICATIONS' && 'Central de Notificações'}
              </h1>
            </div>
            <div className="hidden md:flex items-center space-x-4">
                <button 
                    onClick={handleLogout}
                    className="text-sm text-gray-500 hover:text-gray-700 underline"
                >
                    Sair
                </button>
                <div className="h-10 w-10 rounded-full bg-gradient-to-r from-primary-500 to-orange-600 flex items-center justify-center text-white font-bold shadow-md">
                    {currentUser.name.charAt(0).toUpperCase()}
                </div>
            </div>
            {/* Mobile Logout (shown below header on mobile) */}
            <div className="md:hidden w-full flex justify-end">
                <button 
                    onClick={handleLogout}
                    className="text-sm text-gray-500 border border-gray-200 px-3 py-1 rounded-lg"
                >
                    Sair
                </button>
            </div>
          </header>
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, TicketPriority, TicketStatus } from '../types';
import { AlertCircle, CheckCircle, Clock, Search, Plus, Filter, ArrowUpDown, FileSpreadsheet, LayoutList, KanbanSquare } from 'lucide-react';
import * as XLSX from 'xlsx';
import { TicketKanban } from './TicketKanban';

interface TicketListProps {
  tickets: Ticket[];
  onSelectTicket: (ticket: Ticket) => void;
  onCreateTicket: () => void;
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  initialStatusFilter?: string; // Nova prop opcional
}

export const TicketList: React.FC<TicketListProps> = ({ tickets, onSelectTicket, onCreateTicket, onUpdateStatus, initialStatusFilter = 'ALL' }) => {

  // View Mode
  const [viewMode, setViewMode] = useState<'list' | 'kanban'>('list');

  // Filtros States
  const [searchText, setSearchText] = useState('');
  // Inicializa com o valor da prop (padrão é 'ALL' se não for passado)
  const [statusFilter, setStatusFilter] = useState<string>(initialStatusFilter);
  const [categoryFilter, setCategoryFilter] = useState<string>('ALL');
  const [requesterFilter, setRequesterFilter] = useState<string>('ALL');

  // Date Filters
  const [dateType, setDateType] = useState<'created' | 'resolved' | 'updated'>('created');
  const [dateValue, setDateValue] = useState('');

  // Ordenação
  const [sortField, setSortField] = useState<keyof Ticket>('createdAt');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');

  // Efeito para atualizar o filtro se a prop mudar (ex: navegar entre menus)
  useEffect(() => {
      setStatusFilter(initialStatusFilter);
  }, [initialStatusFilter]);

  // Lógica de Filtragem
  const filteredTickets = useMemo(() => {
    return tickets.filter(ticket => {
      const searchLower = searchText.toLowerCase();

      // 1. Filtro de Texto (ID, Assunto)
      const matchesText = 
        ticket.title.toLowerCase().includes(searchLower) ||
        ticket.ticketNumber.toString().includes(searchLower) ||
        ticket.description.toLowerCase().includes(searchLower);

      // 2. Filtro de Status
      const matchesStatus = statusFilter === 'ALL' || ticket.status === statusFilter;

      // 3. Filtro de Categoria
      const matchesCategory = categoryFilter === 'ALL' || ticket.category === categoryFilter;

      // 4. Filtro de Solicitante (Usuário)
      const matchesRequester = requesterFilter === 'ALL' || ticket.requester === requesterFilter;

      // 5. Filtro de Data (Com correção de Fuso Horário Local)
      let matchesDate = true;
      if (dateValue) {
        let ticketDate: Date | undefined;

        if (dateType === 'created') ticketDate = ticket.createdAt;
        else if (dateType === 'resolved') ticketDate = ticket.resolvedAt;
        else if (dateType === 'updated') ticketDate = ticket.updatedAt;

        if (ticketDate) {
            // Converte ambas as datas para string YYYY-MM-DD usando o horário local do navegador
            const tYear = ticketDate.getFullYear();
            const tMonth = String(ticketDate.getMonth() + 1).padStart(2, '0');
            const tDay = String(ticketDate.getDate()).padStart(2, '0');
            const ticketDateStr = `${tYear}-${tMonth}-${tDay}`;

            matchesDate = ticketDateStr === dateValue;
        } else {
            // Se está filtrando por data de resolução mas o ticket não tem essa data
            matchesDate = false; 
        }
      }

      return matchesText && matchesStatus && matchesCategory && matchesRequester && matchesDate;
    }).sort((a, b) => {
        // Lógica de Ordenação
        const valA = a[sortField];
        const valB = b[sortField];

        if (valA === undefined) return 1; // Move undefined to bottom
        if (valB === undefined) return -1;

        if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
        if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
        return 0;
    });
  }, [tickets, searchText, statusFilter, categoryFilter, requesterFilter, dateType, dateValue, sortField, sortDirection]);

  const clearFilters = () => {
      setSearchText('');
      setStatusFilter('ALL');
      setCategoryFilter('ALL');
      setRequesterFilter('ALL');
      setDateValue('');
      setDateType('created');
  };

  const handleSort = (field: keyof Ticket) => {
      if (sortField === field) {
          setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
      } else {
          setSortField(field);
          setSortDirection('desc'); // Padrão desc ao trocar coluna
      }
  };

  const translateStatusText = (s: string) => {
    switch(s) {
        case 'OPEN': return 'Aberto';
        case 'IN_PROGRESS': return 'Em Progresso';
        case 'RESOLVED': return 'Resolvido';
        default: return s;
    }
  };

  const translatePriorityText = (p: string) => {
    switch(p) {
        case 'LOW': return 'Baixa';
        case 'MEDIUM': return 'Média';
        case 'HIGH': return 'Alta';
        case 'CRITICAL': return 'Crítica';
        default: return p;
    }
  };

  const handleExportXLSX = () => {
    if (filteredTickets.length === 0) {
        alert("Não há chamados para exportar com os filtros atuais.");
        return;
    }

    // Prepara os dados formatados
    const dataToExport = filteredTickets.map(ticket => ({
        "ID": ticket.ticketNumber,
        "Assunto": ticket.title,
        "Descrição": ticket.description,
        "Solicitante": ticket.requester,
        "Categoria": ticket.category,
        "Prioridade": translatePriorityText(ticket.priority),
        "Status": translateStatusText(ticket.status),
        "Data Abertura": ticket.createdAt ? ticket.createdAt.toLocaleString('pt-BR') : '',
        "Data Resolução": ticket.resolvedAt ? ticket.resolvedAt.toLocaleString('pt-BR') : '',
        "Última Atualização": ticket.updatedAt ? ticket.updatedAt.toLocaleString('pt-BR') : ''
    }));

    // Cria a planilha (Worksheet)
    const ws = XLSX.utils.json_to_sheet(dataToExport);

    // Configura a largura das colunas
    const wscols = [
        { wch: 10 }, // ID
        { wch: 40 }, // Assunto
        { wch: 60 }, // Descrição
        { wch: 20 }, // Solicitante
        { wch: 15 }, // Categoria
        { wch: 12 }, // Prioridade
        { wch: 15 }, // Status
        { wch: 20 }, // Data Abertura
        { wch: 20 }, // Data Resolução
        { wch: 20 }  // Ultima Atualização
    ];
    ws['!cols'] = wscols;

    // Cria o arquivo (Workbook) e adiciona a planilha
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Chamados");

    // Gera o arquivo e força o download
    XLSX.writeFile(wb, `chamados_export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const SortIcon = ({ field }: { field: keyof Ticket }) => {
      if (sortField !== field) return <ArrowUpDown size={12} className="ml-1 opacity-30" />;
      return <ArrowUpDown size={12} className={`ml-1 ${sortDirection === 'asc' ? 'text-primary-600' : 'text-primary-600 transform rotate-180'}`} />;
  };

  const getStatusBadge = (s: TicketStatus) => {
    switch(s) {
      case TicketStatus.RESOLVED: 
          return (
            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800 whitespace-nowrap">
                <CheckCircle size={12} className="mr-1" /> Resolvido
            </span>
          );
      case TicketStatus.IN_PROGRESS: 
          return (
            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 whitespace-nowrap">
                <Clock size={12} className="mr-1" /> Em Progresso
            </span>
          );
      default: 
          return (
            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800 whitespace-nowrap">
                <AlertCircle size={12} className="mr-1" /> Aberto
            </span>
          );
    }
  };

  const getPriorityBadge = (p: TicketPriority) => {
    let colorClass = '';
    let label = '';
    switch(p) {
        case TicketPriority.LOW: colorClass = 'bg-green-50 text-green-700 border-green-100'; label = 'Baixa'; break;
        case TicketPriority.MEDIUM: colorClass = 'bg-yellow-50 text-yellow-700 border-yellow-100'; label = 'Média'; break;
        case TicketPriority.HIGH: colorClass = 'bg-orange-50 text-orange-700 border-orange-100'; label = 'Alta'; break;
        case TicketPriority.CRITICAL: colorClass = 'bg-red-50 text-red-700 border-red-100'; label = 'Crítica'; break;
        default: colorClass = 'bg-gray-50 text-gray-700'; label = p;
    }
    return <span className={`px-2 py-1 rounded border text-xs font-medium ${colorClass}`}>{label}</span>;
  };

  const formatDate = (date?: Date) => {
      if (!date) return '-';
      return date.toLocaleDateString('pt-BR', {
          day: '2-digit', month: '2-digit', year: '2-digit',
          hour: '2-digit', minute: '2-digit'
      });
  };

  // Listas únicas para os dropdowns
  const uniqueCategories = Array.from(new Set(tickets.map(t => t.category))).sort();
  const uniqueRequesters = Array.from(new Set(tickets.map(t => t.requester))).sort();

  return (
    <div className="space-y-6">
      {/* Header Actions & Filters */}
      <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm space-y-4">
          <div className="flex flex-col lg:flex-row gap-4 justify-between items-start lg:items-center">
             <div className="relative flex-1 w-full">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                <input 
                    type="text" 
                    value={searchText}
                    onChange={(e) => setSearchText(e.target.value)}
                    placeholder="Buscar por ID, assunto ou descrição..." 
                    className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                />
             </div>

             <div className="flex flex-col sm:flex-row gap-2 w-full lg:w-auto">
                 {/* View Toggle */}
                 <div className="flex bg-gray-100 p-1 rounded-lg border border-gray-200">
                    <button
                        onClick={() => setViewMode('list')}
                        className={`p-1.5 rounded-md transition-all ${viewMode === 'list' ? 'bg-white shadow text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
                        title="Visualização em Lista"
                    >
                        <LayoutList size={18} />
                    </button>
                    <button
                        onClick={() => setViewMode('kanban')}
                        className={`p-1.5 rounded-md transition-all ${viewMode === 'kanban' ? 'bg-white shadow text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
                        title="Visualização em Kanban"
                    >
                        <KanbanSquare size={18} />
                    </button>
                 </div>

                 <button 
                    onClick={handleExportXLSX}
                    className="flex-1 lg:flex-none flex items-center justify-center space-x-2 px-4 py-2 bg-white border border-gray-300 text-green-700 rounded-lg hover:bg-green-50 transition-colors shadow-sm text-sm font-medium whitespace-nowrap"
                    title="Exportar dados filtrados para Excel"
                 >
                    <FileSpreadsheet size={18} />
                    <span className="hidden sm:inline">Exportar</span>
                 </button>
                 <button 
                    onClick={onCreateTicket}
                    className="flex-1 lg:flex-none flex items-center justify-center space-x-2 px-5 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors shadow-sm text-sm font-medium whitespace-nowrap"
                >
                    <Plus size={18} />
                    <span>Novo Chamado</span>
                 </button>
             </div>
          </div>

          {/* Advanced Filters Row */}
          <div className="flex flex-col xl:flex-row gap-3 items-start xl:items-center">
             <div className="flex items-center gap-2 w-full xl:w-auto mb-2 xl:mb-0">
                <Filter size={16} className="text-gray-500" />
                <span className="text-sm font-medium text-gray-700">Filtros:</span>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3 w-full flex-1">
                {/* Status Filter */}
                <select 
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm text-gray-600 outline-none bg-white focus:border-primary-500"
                >
                    <option value="ALL">Todos os Status</option>
                    <option value="OPEN">Aberto</option>
                    <option value="IN_PROGRESS">Em Progresso</option>
                    <option value="RESOLVED">Resolvido</option>
                </select>

                {/* Category Filter */}
                <select 
                    value={categoryFilter}
                    onChange={(e) => setCategoryFilter(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm text-gray-600 outline-none bg-white focus:border-primary-500"
                >
                    <option value="ALL">Todas Categorias</option>
                    {uniqueCategories.map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                    ))}
                </select>

                {/* Requester Filter */}
                <select 
                    value={requesterFilter}
                    onChange={(e) => setRequesterFilter(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm text-gray-600 outline-none bg-white focus:border-primary-500"
                >
                    <option value="ALL">Todos Solicitantes</option>
                    {uniqueRequesters.map(req => (
                        <option key={req} value={req}>{req}</option>
                    ))}
                </select>

                {/* Date Filter Group */}
                <div className="flex items-center gap-0 border border-gray-200 rounded-lg overflow-hidden w-full">
                     <select
                        value={dateType}
                        onChange={(e) => setDateType(e.target.value as any)}
                        className="bg-gray-50 text-xs font-medium text-gray-600 outline-none px-2 py-2.5 border-r border-gray-200 w-24"
                     >
                         <option value="created">Abertura</option>
                         <option value="resolved">Resolução</option>
                         <option value="updated">Atualiz.</option>
                     </select>
                     <input 
                        type="date"
                        value={dateValue}
                        onChange={(e) => setDateValue(e.target.value)}
                        className="flex-1 px-2 py-2 text-sm text-gray-600 outline-none bg-white"
                     />
                </div>
             </div>

             {(searchText || statusFilter !== 'ALL' || categoryFilter !== 'ALL' || requesterFilter !== 'ALL' || dateValue) && (
                 <button 
                    onClick={clearFilters}
                    className="text-xs text-red-500 font-medium hover:underline whitespace-nowrap px-2"
                 >
                    Limpar Filtros
                 </button>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      {viewMode === 'kanban' ? (
          <TicketKanban 
            tickets={filteredTickets} 
            onSelectTicket={onSelectTicket}
            onUpdateStatus={onUpdateStatus}
          />
      ) : (
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-100 text-gray-500 uppercase text-[11px] font-semibold tracking-wider">
                        <tr>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('ticketNumber')}>
                                <div className="flex items-center">ID <SortIcon field="ticketNumber" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('title')}>
                                <div className="flex items-center">Assunto <SortIcon field="title" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('requester')}>
                                <div className="flex items-center">Solicitante <SortIcon field="requester" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('category')}>
                                <div className="flex items-center">Categoria <SortIcon field="category" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('priority')}>
                                <div className="flex items-center">Prioridade <SortIcon field="priority" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('createdAt')}>
                                <div className="flex items-center">Data Abertura <SortIcon field="createdAt" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('resolvedAt')}>
                                <div className="flex items-center">Data Resolução <SortIcon field="resolvedAt" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100" onClick={() => handleSort('updatedAt')}>
                                <div className="flex items-center">Última At. <SortIcon field="updatedAt" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer hover:bg-gray-100 text-right" onClick={() => handleSort('status')}>
                                <div className="flex items-center justify-end">Status <SortIcon field="status" /></div>
                            </th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {filteredTickets.map((ticket) => (
                            <tr 
                                key={ticket.id} 
                                onClick={() => onSelectTicket(ticket)}
                                className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                            >
                                <td className="px-6 py-4 text-sm font-medium text-gray-500">
                                    #{ticket.ticketNumber}
                                </td>
                                <td className="px-6 py-4">
                                    <div>
                                        <p className="text-sm font-semibold text-gray-900 group-hover:text-primary-600 transition-colors">{ticket.title}</p>
                                        <p className="text-xs text-gray-500 truncate max-w-[150px] md:max-w-[300px]">{ticket.description}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-700 font-medium">
                                    {ticket.requester}
                                </td>
                                <td className="px-6 py-4">
                                    <span className="px-2 py-1 bg-gray-100 rounded text-xs font-medium text-gray-600 border border-gray-200">
                                        {ticket.category}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    {getPriorityBadge(ticket.priority)}
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">
                                    {formatDate(ticket.createdAt)}
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">
                                    {formatDate(ticket.resolvedAt)}
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">
                                    {formatDate(ticket.updatedAt)}
                                </td>
                                <td className="px-6 py-4 text-right">
                                    {getStatusBadge(ticket.status)}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>

                {filteredTickets.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-16 text-center">
                        <div className="bg-gray-50 p-4 rounded-full mb-3">
                            <Search size={24} className="text-gray-400" />
                        </div>
                        <p className="text-gray-900 font-medium">Nenhum chamado encontrado.</p>
                        <p className="text-sm text-gray-500 mt-1">Tente ajustar seus filtros ou crie um novo chamado.</p>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { TicketDetail } from './components/TicketDetail';
import { Login } from './components/Login';
import { UserManagement } from './components/UserManagement';
import { Notifications } from './components/Notifications';
import { Dashboard } from './components/Dashboard';
import { Ticket, ViewState, TicketStatus, User } from './types';
import { supabase } from './services/supabase';
import { Loader2, Menu } from 'lucide-react';
import { Logo } from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [ticketToEdit, setTicketToEdit] = useState<Ticket | null>(null);
  const [loading, setLoading] = useState(true);

  // Mobile Sidebar State
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Check auth session on load
  useEffect(() => {
    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            fetchProfile(session.user.id, session.user.email!);
        } else {
            setCurrentUser(null);
            setTickets([]);
            setLoading(false);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch tickets whenever user changes or view updates
  useEffect(() => {
      if (currentUser) {
          fetchTickets();
      }
  }, [currentUser, currentView]);

  const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
          await fetchProfile(session.user.id, session.user.email!);
      } else {
          setLoading(false);
      }
  };

  const fetchProfile = async (userId: string, email: string) => {
      try {
          // 1. Get Auth Metadata to ensure we have the real name entered during sign up
          const { data: authUser } = await supabase.auth.getUser();
          const metaName = authUser.user?.user_metadata?.full_name;

          // Fallback name logic: Metadata > Email
          const displayName = metaName || email.split('@')[0];

          // 2. Attempt to fetch profile from DB
          let { data, error } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', userId)
            .maybeSingle();

          // 3. SELF-HEALING: If profile is missing but Auth exists, create it now.
          if (!data) {
            console.log("Profile missing for authenticated user. Creating default 'USER' profile...");

            const { data: newProfile, error: createError } = await supabase
                .from('profiles')
                .insert([{ 
                    id: userId, 
                    email: email, 
                    name: displayName, // Uses the real name from registration if available
                    role: 'USER', // Enforced default role
                    is_active: true
                }])
                .select()
                .single();

            if (createError) {
                console.error("Failed to auto-create profile:", createError);
                throw createError;
            }
            data = newProfile;
          } else if (error) {
            throw error;
          }

          // 4. Check for INACTIVE status
          if (data.is_active === false) {
              alert("Sua conta foi desativada pelo administrador. Entre em contato com o suporte.");
              await supabase.auth.signOut();
              setCurrentUser(null);
              setLoading(false);
              return;
          }

          // 5. SPECIAL ADMIN OVERRIDE (Bootstrap)
          const superAdmins = ['ti@grupoairslaid.com.br'];
          if (superAdmins.includes(email) || email.startsWith('admin') || email.startsWith('dev')) {
             if (data && data.role !== 'ADMIN') {
                 console.log(`Promoting super user ${email} to ADMIN...`);
                 await supabase.from('profiles').update({ role: 'ADMIN' }).eq('id', userId);
                 data.role = 'ADMIN';
             }
          }

          if (data) {
            setCurrentUser({
                id: data.id,
                name: data.name, // Use DB name (which we ensured matches metadata on creation)
                email: data.email || email,
                role: data.role,
                isActive: data.is_active
            });
          }
      } catch (error) {
          console.error('Error fetching/creating profile:', error);
      } finally {
          setLoading(false);
      }
  };

  const fetchTickets = async () => {
      try {
          // Alterado para fazer JOIN com a tabela profiles e pegar o nome atualizado
          const { data, error } = await supabase
            .from('tickets')
            .select('*, profiles:requester_id(name)')
            .order('created_at', { ascending: false });

          if (error) throw error;

          const formattedTickets: Ticket[] = data.map((t: any) => ({
              id: t.id,
              ticketNumber: t.ticket_number || 0,
              title: t.title,
              description: t.description,
              // Usa o nome do perfil (atualizado) se existir, senão usa o nome gravado no ticket (backup)
              requester: t.profiles?.name || t.requester_name,
              requesterId: t.requester_id,
              priority: t.priority,
              status: t.status,
              category: t.category,
              createdAt: new Date(t.created_at),
              updatedAt: t.updated_at ? new Date(t.updated_at) : new Date(t.created_at),
              resolvedAt: t.resolved_at ? new Date(t.resolved_at) : undefined,
              attachments: t.attachments || []
          }));

          setTickets(formattedTickets);
      } catch (error) {
          console.error('Error fetching tickets:', error);
      }
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      setCurrentView('DASHBOARD');
  };

  const handleCreateTicket = async (newTicketData: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => {
    if (!currentUser) return;

    try {
        if (ticketToEdit) {
            // Update existing ticket
            const { error } = await supabase
                .from('tickets')
                .update({
                    title: newTicketData.title,
                    description: newTicketData.description,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: newTicketData.status,
                    attachments: newTicketData.attachments
                })
                .eq('id', ticketToEdit.id);

            if (error) throw error;

            // Audit Log for Edit
            await supabase.from('audit_logs').insert({
                ticket_id: ticketToEdit.id,
                actor_id: currentUser.id,
                action: 'EDITED',
                details: 'Detalhes do chamado editados'
            });

            setTicketToEdit(null);
        } else {
            // Create new ticket
            // ticket_number is generated automatically by Postgres
            const { data: newTicket, error } = await supabase
                .from('tickets')
                .insert([{
                    title: newTicketData.title,
                    description: newTicketData.description,
                    requester_name: currentUser?.name, 
                    requester_id: currentUser?.id,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: 'OPEN',
                    attachments: newTicketData.attachments
                }])
                .select()
                .single();

            if (error) throw error;

            if (newTicket) {
                // Audit Log for Creation
                await supabase.from('audit_logs').insert({
                    ticket_id: newTicket.id,
                    actor_id: currentUser.id,
                    action: 'CREATED',
                    details: `Chamado criado com prioridade ${newTicketData.priority}`
                });

                // NOTIFICATION LOGIC: Notify all Admins
                const { data: admins } = await supabase.from('profiles').select('id').eq('role', 'ADMIN');
                if (admins && admins.length > 0) {
                    const notifications = admins.map(admin => ({
                        user_id: admin.id,
                        title: 'Novo Chamado Criado',
                        message: `${currentUser?.name} abriu um novo chamado: ${newTicketData.title}`,
                        ticket_id: newTicket.id
                    }));
                    await supabase.from('notifications').insert(notifications);
                }
            }
        }

        await fetchTickets(); // Refresh list

        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS'); // Return to list view after edit/create
        }
    } catch (error) {
        console.error("Error saving ticket:", error);
        alert("Falha ao salvar chamado. Por favor, tente novamente.");
    }
  };

  const handleSelectTicket = (ticket: Ticket) => {
    setSelectedTicket(ticket);
    setCurrentView('TICKET_DETAIL');
  };

  const handleSelectNotificationTicket = async (ticketId: string) => {
      // Find the ticket in the current list or fetch it
      const existing = tickets.find(t => t.id === ticketId);
      if (existing) {
          setSelectedTicket(existing);
          setCurrentView('TICKET_DETAIL');
      } else {
          // Fallback fetch if not loaded
          const { data } = await supabase.from('tickets').select('*, profiles:requester_id(name)').eq('id', ticketId).single();
          if (data) {
             const formatted: Ticket = {
                id: data.id,
                ticketNumber: data.ticket_number,
                title: data.title,
                description: data.description,
                requester: data.profiles?.name || data.requester_name,
                requesterId: data.requester_id,
                priority: data.priority,
                status: data.status,
                category: data.category,
                createdAt: new Date(data.created_at),
                updatedAt: data.updated_at ? new Date(data.updated_at) : new Date(data.created_at),
                resolvedAt: data.resolved_at ? new Date(data.resolved_at) : undefined,
                attachments: data.attachments || []
             };
             setSelectedTicket(formatted);
             setCurrentView('TICKET_DETAIL');
          }
      }
  };

  const handleDeleteTicket = async (id: string) => {
      try {
        const { error } = await supabase.from('tickets').delete().eq('id', id);
        if (error) throw error;

        setTickets(tickets.filter(t => t.id !== id));
        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS');
        }
      } catch (error) {
          console.error("Error deleting ticket:", error);
          alert("Falha ao excluir chamado.");
      }
  };

  const handleEditTicket = (ticket: Ticket) => {
      setTicketToEdit(ticket);
      setCurrentView('EDIT_TICKET');
  };

  const handleUpdateStatus = async (id: string, status: TicketStatus) => {
    if (!currentUser) return;

    try {
        // Prepare update data
        const updates: any = { status };

        // Logic for Resolved Date
        if (status === TicketStatus.RESOLVED) {
            updates.resolved_at = new Date().toISOString();
        } else {
            // If reopening, maybe clear resolved_at? 
            // updates.resolved_at = null; // Optional: Uncomment if reopening should clear the date
        }

        const { error } = await supabase
            .from('tickets')
            .update(updates)
            .eq('id', id);

        if (error) throw error;

        // Audit Log for Status Change
        await supabase.from('audit_logs').insert({
            ticket_id: id,
            actor_id: currentUser.id,
            action: 'STATUS_CHANGE',
            details: `Status alterado para ${status}`
        });

        // Update local state immediately (Optimistic or Fetch)
        setTickets(prev => prev.map(t => {
            if (t.id === id) {
                return {
                    ...t,
                    status,
                    resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : t.resolvedAt,
                    updatedAt: new Date() // Optimistic update for Last Update
                };
            }
            return t;
        }));

        if (selectedTicket && selectedTicket.id === id) {
            const updatedTicket = { 
                ...selectedTicket, 
                status,
                resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : selectedTicket.resolvedAt,
                updatedAt: new Date()
            };
            setSelectedTicket(updatedTicket);

            // NOTIFICATION LOGIC: Notify the requester if status changes
            // If I am an admin changing a user's ticket
            if (currentUser.role === 'ADMIN') {
                const { data: profile } = await supabase.from('profiles').select('name').eq('id', currentUser.id).single();
                const adminName = profile?.name || 'Admin';

                // Don't notify if I am the requester too
                if (selectedTicket.requesterId !== currentUser.id) {
                    await supabase.from('notifications').insert({
                        user_id: selectedTicket.requesterId,
                        title: 'Status Atualizado',
                        message: `Seu chamado "${selectedTicket.title}" mudou para ${status} por ${adminName}.`,
                        ticket_id: id
                    });
                }
            }
        }
    } catch (error) {
        console.error("Error updating status:", error);
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (currentView) {
      case 'CREATE_TICKET':
      case 'EDIT_TICKET':
        return (
          <TicketForm 
            onSave={handleCreateTicket} 
            onCancel={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} 
            initialData={currentView === 'EDIT_TICKET' ? ticketToEdit || undefined : undefined}
            currentUser={currentUser}
          />
        );
      case 'TICKET_DETAIL':
        return selectedTicket ? (
          <TicketDetail 
            ticket={selectedTicket}
            currentUser={currentUser}
            onBack={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')}
            onUpdateStatus={handleUpdateStatus}
            onDelete={handleDeleteTicket}
            onEdit={handleEditTicket}
          />
        ) : (
           <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
           />
        );
      case 'USERS':
        return currentUser.role === 'ADMIN' ? <UserManagement currentUser={currentUser} /> : <div>Acesso Negado</div>;
      case 'NOTIFICATIONS':
        return <Notifications currentUser={currentUser} onSelectNotification={handleSelectNotificationTicket} />;
      case 'MY_TICKETS':
        return (
            <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
            />
        );
      case 'ALL_TICKETS':
        return (
            <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
                initialStatusFilter={TicketStatus.OPEN} // Filtra apenas ABERTOS por padrão
            />
        );
      case 'DASHBOARD':
      default:
        return <Dashboard tickets={tickets} currentUser={currentUser} onCreateTicket={() => setCurrentView('CREATE_TICKET')} />;
    }
  };

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <Loader2 className="animate-spin text-primary-600" size={48} />
          </div>
      );
  }

  if (!currentUser) {
    return <Login onLoginSuccess={() => checkUser()} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        currentUser={currentUser} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 w-full bg-white z-30 border-b border-gray-200 px-4 py-3 flex items-center justify-between">
          <div className="flex items-center space-x-3">
              <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="p-1 text-gray-600 hover:bg-gray-100 rounded-lg"
              >
                  <Menu size={24} />
              </button>
