             </div>
             <div className="hidden md:block bg-white/10 p-3 rounded-lg backdrop-blur-sm">
                <FileText size={24} className="text-white" />
             </div>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">

          {/* Seção 1: Informações Básicas */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Solicitante</label>
                    <input
                        type="text"
                        value={currentUser.name}
                        disabled
                        className="w-full px-4 py-2.5 border border-gray-200 rounded-lg bg-gray-50 text-gray-500 cursor-not-allowed font-medium"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Categoria</label>
                    <div className="relative">
                        <select
                            value={category}
                            onChange={(e) => setCategory(e.target.value)}
                            className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white appearance-none cursor-pointer hover:border-primary-400 transition-colors"
                        >
                            {CATEGORIES.map(cat => (
                                <option key={cat} value={cat}>{cat}</option>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                            <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                        </div>
                    </div>
                </div>
             </div>

             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Assunto</label>
                    <input
                        type="text"
                        required
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all placeholder-gray-400"
                        placeholder="Ex: Erro ao acessar o ERP"
                    />
                </div>
             </div>
          </div>

          <div className="border-t border-gray-100 my-2"></div>

          {/* Seção 2: Detalhes e Prioridade */}
          <div className="space-y-6">
             <div>
                <div className="flex justify-between items-center mb-2">
                    <label className="block text-sm font-medium text-gray-700">Descrição Detalhada</label>

                    {/* Botão de IA */}
                    <button
                        type="button"
                        onClick={handleAiClassification}
                        disabled={isAnalysing || !description}
                        className={`
                           flex items-center text-xs px-3 py-1.5 rounded-full transition-all border
                           ${isAnalysing 
                             ? 'bg-purple-100 text-purple-700 border-purple-200' 
                             : 'bg-gradient-to-r from-purple-500 to-indigo-600 text-white border-transparent hover:shadow-md hover:scale-105'}
                           ${!description ? 'opacity-50 cursor-not-allowed' : ''}
                        `}
                    >
                        {isAnalysing ? (
                            <>
                                <Loader2 size={12} className="animate-spin mr-1.5" />
                                Analisando...
                            </>
                        ) : (
                            <>
                                <Sparkles size={12} className="mr-1.5" />
                                Sugerir Categoria e Prioridade
                            </>
                        )}
                    </button>
                </div>

                <div className="relative">
                    <textarea
                        required
                        rows={6}
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all resize-none leading-relaxed"
                        placeholder="Descreva o que aconteceu, quais passos você seguiu e se apareceu alguma mensagem de erro..."
                    />
                    <div className="absolute bottom-3 right-3 text-xs text-gray-400 pointer-events-none">
                        Quanto mais detalhes, mais rápido resolvemos.
                    </div>
                </div>

                {/* Feedback da IA */}
                {aiReasoning && (
                    <div className="mt-3 bg-purple-50 border border-purple-100 rounded-lg p-3 flex items-start animate-fade-in">
                        <Wand2 size={16} className="text-purple-600 mr-2 mt-0.5 flex-shrink-0" />
                        <div>
                            <p className="text-xs font-bold text-purple-800 mb-0.5">Sugestão da IA Aplicada</p>
                            <p className="text-xs text-purple-700">{aiReasoning}</p>
                        </div>
                    </div>
                )}
             </div>

             <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">Defina a Prioridade</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3">
                    {PRIORITY_OPTIONS.map((option) => (
                        <button
                            key={option.id}
                            type="button"
                            onClick={() => setPriority(option.id)}
                            className={`
                                relative flex flex-col items-start p-3 rounded-xl border transition-all duration-200 text-left
                                ${priority === option.id ? option.selectedClass : 'border-gray-200 bg-white text-gray-600 ' + option.colorClass}
                            `}
                        >
                            <div className="flex items-center justify-between w-full mb-1">
                                <span className="font-bold text-sm">{option.label}</span>
                                {priority === option.id && <Check size={16} className="text-current" />}
                            </div>
                            <span className="text-xs opacity-80">{option.desc}</span>
                        </button>
                    ))}
                </div>
             </div>

             {/* Attachments Section */}
             <div className="bg-gray-50 rounded-lg p-4 border border-dashed border-gray-300">
                  <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                      <div>
                          <label className="block text-sm font-medium text-gray-700">Anexos (Opcional)</label>
                          <p className="text-xs text-gray-500 mt-1">Adicione prints ou documentos para ajudar.</p>
                      </div>

                      <label className={`
                          flex flex-col md:flex-row items-center justify-center space-x-0 md:space-x-2 px-4 py-2 rounded-lg transition-all shadow-sm w-full md:w-auto min-w-[160px] relative overflow-hidden
                          ${isUploading 
                            ? 'bg-gray-50 border border-gray-200 cursor-not-allowed h-12' 
                            : 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-100 cursor-pointer h-10'}
                      `}>
                          {isUploading ? (
                              <div className="w-full px-2 flex flex-col justify-center h-full">
                                  <div className="flex justify-between items-center mb-1 w-full">
                                      <span className="text-xs font-semibold text-primary-700 flex items-center">
                                          <Loader2 size={10} className="animate-spin mr-1" />
                                          Enviando...
                                      </span>
                                      <span className="text-xs font-bold text-primary-700">{uploadProgress}%</span>
                                  </div>
                                  <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden">
                                      <div 
                                        className="bg-primary-600 h-1.5 rounded-full transition-all duration-300 ease-out" 
                                        style={{ width: `${uploadProgress}%` }}
                                      ></div>
                                  </div>
                              </div>
                          ) : (
                              <>
                                <Paperclip size={18} />
                                <span className="text-sm font-medium">Selecionar Arquivo</span>
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    onChange={handleFileUpload} 
                                    disabled={isUploading}
                                />
                              </>
                          )}
                      </label>
                  </div>

                  {attachments.length > 0 && (
                      <div className="mt-4 grid grid-cols-1 sm:grid-cols-2 gap-2">
                          {attachments.map((url, index) => (
                              <div key={index} className="flex items-center justify-between bg-white px-3 py-2 rounded border border-gray-200 shadow-sm animate-blob">
                                  <div className="flex items-center space-x-2 overflow-hidden">
                                      <div className="bg-blue-50 p-1.5 rounded text-blue-500">
                                        <FileText size={14} />
                                      </div>
                                      <a href={url} target="_blank" rel="noreferrer" className="text-xs font-medium text-gray-700 hover:text-blue-600 hover:underline truncate max-w-[150px]">
                                          Anexo {index + 1}
                                      </a>
                                  </div>
                                  <button 
                                    type="button" 
                                    onClick={() => removeAttachment(url)}
                                    className="text-gray-400 hover:text-red-500 p-1 rounded-full hover:bg-red-50 transition-colors"
                                  >
                                      <X size={14} />
                                  </button>
                              </div>
                          ))}
                      </div>
                  )}
             </div>
          </div>

          <div className="pt-6 flex flex-col-reverse md:flex-row justify-end gap-3 md:gap-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 font-medium transition-colors w-full md:w-auto text-center"
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={isUploading || isAnalysing}
              className={`px-8 py-2.5 text-white rounded-lg font-medium shadow-lg transition-all w-full md:w-auto text-center flex justify-center items-center
                ${isUploading || isAnalysing
                    ? 'bg-primary-400 cursor-not-allowed' 
                    : 'bg-primary-600 hover:bg-primary-700 hover:shadow-xl hover:-translate-y-0.5'}
              `}
            >
              {isUploading && <Loader2 size={18} className="animate-spin mr-2" />}
              {initialData ? 'Salvar Alterações' : 'Criar Chamado'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Ticket, TicketStatus, User, Comment, AuditLog } from '../types';
import { ArrowLeft, CheckCircle, Clock, User as UserIcon, Calendar, Tag, Trash2, Edit, Send, MessageSquare, FileText, Paperclip, Sparkles, Bot, Loader2 } from 'lucide-react';
import { supabase } from '../services/supabase';
import { getGeminiInsights } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface TicketDetailProps {
  ticket: Ticket;
  currentUser: User;
  onBack: () => void;
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  onDelete: (id: string) => void;
  onEdit: (ticket: Ticket) => void;
}

export const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, currentUser, onBack, onUpdateStatus, onDelete, onEdit }) => {
  // Comment State
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loadingComments, setLoadingComments] = useState(true);
  const commentsEndRef = useRef<HTMLDivElement>(null);

  // Audit Logs State
  const [logs, setLogs] = useState<AuditLog[]>([]);

  // AI State
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const isAdmin = currentUser.role === 'ADMIN';
  const isOwner = currentUser.id === ticket.requesterId;

  useEffect(() => {
      fetchComments();
      fetchLogs();

      // Subscribe to new comments
      const channel = supabase
        .channel(`comments:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'comments', filter: `ticket_id=eq.${ticket.id}` }, (payload) => {
            fetchComments(); 
        })
        .subscribe();

      // Subscribe to logs
      const logsChannel = supabase
        .channel(`logs:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'audit_logs', filter: `ticket_id=eq.${ticket.id}` }, () => {
            fetchLogs();
        })
        .subscribe();

      return () => {
          supabase.removeChannel(channel);
          supabase.removeChannel(logsChannel);
      }
  }, [ticket.id]);

  useEffect(() => {
      commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [comments]);

  const fetchComments = async () => {
      const { data, error } = await supabase
        .from('comments')
        .select('*, profiles(name, role)')
        .eq('ticket_id', ticket.id)
        .order('created_at', { ascending: true });

      if (error) {
          console.error("Error fetching comments", error);
      } else {
          const formattedComments = data.map((c: any) => ({
              id: c.id,
              ticketId: c.ticket_id,
              userId: c.user_id,
              content: c.content,
              createdAt: new Date(c.created_at),
              userName: c.profiles?.name || 'Desconhecido',
              userRole: c.profiles?.role || 'USER'
          }));
          setComments(formattedComments);
      }
      setLoadingComments(false);
  };

  const fetchLogs = async () => {
    const { data } = await supabase
      .from('audit_logs')
      .select('*, profiles(name)')
      .eq('ticket_id', ticket.id)
      .order('created_at', { ascending: false });

    if (data) {
        setLogs(data.map((l: any) => ({
            id: l.id,
            ticketId: l.ticket_id,
            actorId: l.actor_id,
            actorName: l.profiles?.name || 'Sistema',
            action: l.action,
            details: l.details,
            createdAt: new Date(l.created_at)
        })));
    }
  };

  const handleGenerateInsight = async () => {
      setLoadingAi(true);
      const insight = await getGeminiInsights(ticket.title, ticket.description);
      setAiInsight(insight);
      setLoadingAi(false);
  };

  const handleSendComment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newComment.trim()) return;

      const commentText = newComment;

      // Optimistic Update
      const tempId = `temp-${Date.now()}`;
      const optimisticComment: Comment = {
          id: tempId,
          ticketId: ticket.id,
          userId: currentUser.id,
          userName: currentUser.name,
          userRole: currentUser.role,
          content: commentText,
          createdAt: new Date()
      };

      setComments(prev => [...prev, optimisticComment]);
      setNewComment(''); 

      try {
          const { error } = await supabase.from('comments').insert({
              ticket_id: ticket.id,
              user_id: currentUser.id,
              content: commentText
          });

          if (error) throw error;

          // Notifications
          if (isAdmin) {
             if (ticket.requesterId !== currentUser.id) {
                 await supabase.from('notifications').insert({
                     user_id: ticket.requesterId,
                     title: 'Nova interação no chamado',
                     message: `${currentUser.name} comentou: ${commentText.substring(0, 50)}...`,
                     ticket_id: ticket.id
                 });
             }
          } else {
             const { data: admins } = await supabase.from('profiles').select('id').eq('role', 'ADMIN');
             if (admins) {
                 const notifications = admins.map(admin => ({
                     user_id: admin.id,
                     title: `Nova interação de ${currentUser.name}`,
                     message: `No chamado "${ticket.title}": ${commentText.substring(0, 50)}...`,
                     ticket_id: ticket.id
                 }));
                 if (notifications.length > 0) {
                    await supabase.from('notifications').insert(notifications);
                 }
             }
          }

      } catch (error) {
          console.error("Error sending comment:", error);
          alert("Erro ao enviar mensagem");
          setComments(prev => prev.filter(c => c.id !== tempId));
          setNewComment(commentText); 
      }
  };

  const translatePriority = (p: string) => {
    switch(p) {
        case 'LOW': return 'Baixa';
        case 'MEDIUM': return 'Média';
        case 'HIGH': return 'Alta';
        case 'CRITICAL': return 'Crítica';
        default: return p;
    }
  };

  const translateStatus = (s: string) => {
      switch(s) {
          case 'OPEN': return 'Aberto';
          case 'IN_PROGRESS': return 'Em Progresso';
          case 'RESOLVED': return 'Resolvido';
          default: return s;
      }
  };

  const getLogIcon = (action: string) => {
      switch(action) {
          case 'CREATED': return <CheckCircle size={14} className="text-green-600" />;
          case 'STATUS_CHANGE': return <Clock size={14} className="text-blue-600" />;
          case 'EDITED': return <Edit size={14} className="text-orange-600" />;
          default: return <FileText size={14} className="text-gray-600" />;
      }
  };

  const translateLogAction = (action: string) => {
    switch(action) {
        case 'CREATED': return 'Chamado Criado';
        case 'STATUS_CHANGE': return 'Status Alterado';
        case 'EDITED': return 'Chamado Editado';
        default: return action;
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-gray-700">
        <ArrowLeft size={18} className="mr-2" />
        Voltar para {isAdmin ? 'Dashboard' : 'Meus Chamados'}
      </button>

      {/* Header Card */}
      <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6">
        <div className="flex justify-between items-start">
            <div>
                <div className="flex items-center space-x-3 mb-2">
                    <span className="text-xs font-bold text-gray-400 uppercase tracking-wide">#{ticket.ticketNumber}</span>
                    <span className={`px-2 py-0.5 rounded text-xs font-medium ${
                        ticket.priority === 'CRITICAL' ? 'bg-red-100 text-red-800' : 
                        ticket.priority === 'HIGH' ? 'bg-orange-100 text-orange-800' :
                        ticket.priority === 'MEDIUM' ? 'bg-yellow-100 text-yellow-800' :
                        'bg-blue-100 text-blue-800'
                    }`}>
                        Prioridade {translatePriority(ticket.priority)}
                    </span>
                </div>
                <h1 className="text-2xl font-bold text-gray-900">{ticket.title}</h1>
            </div>

            <div className="flex items-center space-x-3">
                {(isOwner || isAdmin) && (
                     <button 
                        onClick={() => onEdit(ticket)}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Editar Chamado"
                     >
                         <Edit size={20} />
                     </button>
                )}
                {(isOwner || isAdmin) && (
                    <button 
                        onClick={() => {
                            if (window.confirm("Tem certeza que deseja excluir este chamado?")) {
                                onDelete(ticket.id);
                            }
                        }}
                        className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                        title="Excluir Chamado"
                    >
                        <Trash2 size={20} />
                    </button>
                )}
            </div>
        </div>

        <div className="mt-6 flex flex-wrap gap-4 text-sm text-gray-600">
            <div className="flex items-center">
                <UserIcon size={16} className="mr-2 text-gray-400" />
                <span className="font-medium">Solicitante:</span>
                <span className="ml-1">{ticket.requester}</span>
            </div>
            <div className="flex items-center">
                <Calendar size={16} className="mr-2 text-gray-400" />
                <span className="font-medium">Criado em:</span>
                <span className="ml-1">{ticket.createdAt.toLocaleDateString('pt-BR')} às {ticket.createdAt.toLocaleTimeString('pt-BR')}</span>
            </div>
            <div className="flex items-center">
                <Tag size={16} className="mr-2 text-gray-400" />
                <span className="font-medium">Categoria:</span>
                <span className="ml-1 bg-gray-100 px-2 py-0.5 rounded text-xs">{ticket.category}</span>
            </div>
        </div>

        <div className="mt-6 p-4 bg-gray-50 rounded-lg border border-gray-200">
            <h3 className="text-sm font-bold text-gray-900 mb-2">Descrição do Problema</h3>
            <p className="text-gray-700 whitespace-pre-wrap leading-relaxed">{ticket.description}</p>
        </div>

        {/* Attachments View */}
        {ticket.attachments && ticket.attachments.length > 0 && (
            <div className="mt-4">
                <h3 className="text-sm font-bold text-gray-900 mb-2 flex items-center">
                    <Paperclip size={16} className="mr-1 text-gray-500" />
                    Anexos
                </h3>
                <div className="flex flex-wrap gap-2">
                    {ticket.attachments.map((url, index) => (
                        <a 
                            key={index} 
                            href={url} 
                            target="_blank" 
                            rel="noreferrer"
                            className="flex items-center space-x-2 px-3 py-2 bg-white border border-gray-200 rounded-lg shadow-sm hover:bg-blue-50 hover:border-blue-200 transition-colors group"
                        >
                            <FileText size={16} className="text-gray-400 group-hover:text-blue-500" />
                            <span className="text-sm text-gray-700 group-hover:text-blue-700">Anexo {index + 1}</span>
                        </a>
                    ))}
                </div>
            </div>
        )}

        {/* AI Insights Section (Visible to everyone or just Admin? Let's keep for Admins or the Requester to see self-help) */}
        <div className="mt-6 border-t border-gray-100 pt-4">
            {!aiInsight ? (
                 <button
                    onClick={handleGenerateInsight}
                    disabled={loadingAi}
                    className="flex items-center text-sm font-medium text-purple-600 hover:text-purple-800 hover:bg-purple-50 px-3 py-2 rounded-lg transition-colors"
                 >
                     {loadingAi ? <Loader2 size={16} className="animate-spin mr-2" /> : <Sparkles size={16} className="mr-2" />}
                     Gerar Solução Sugerida com IA
                 </button>
            ) : (
                <div className="bg-purple-50 rounded-lg border border-purple-100 p-4 animate-fade-in">
                    <div className="flex items-center justify-between mb-3">
                        <h4 className="flex items-center text-sm font-bold text-purple-900">
                            <Bot size={18} className="mr-2" />
                            Solução Sugerida (IA)
                        </h4>
                        <button onClick={() => setAiInsight(null)} className="text-purple-400 hover:text-purple-600">
                            <Trash2 size={14} />
                        </button>
                    </div>
                    <div className="prose prose-sm prose-purple max-w-none text-gray-700 text-sm">
                        <ReactMarkdown>{aiInsight}</ReactMarkdown>
                    </div>
                    <p className="text-[10px] text-purple-400 mt-3 border-t border-purple-100 pt-2">
                        Gerado automaticamente por Gemini AI. Verifique as informações antes de aplicar.
                    </p>
                </div>
            )}
        </div>

        {isAdmin && (
            <div className="mt-6 flex items-center justify-end space-x-4 pt-4 border-t border-gray-100">
                <span className="text-sm text-gray-500 font-medium">Atualizar Status:</span>
                <div className="flex bg-gray-100 p-1 rounded-lg">
                    {[TicketStatus.OPEN, TicketStatus.IN_PROGRESS, TicketStatus.RESOLVED].map((status) => (
                        <button
                            key={status}
                            onClick={() => onUpdateStatus(ticket.id, status)}
                            className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                                ticket.status === status 
                                ? 'bg-white text-gray-900 shadow-sm' 
                                : 'text-gray-500 hover:text-gray-900'
                            }`}
                        >
                            {translateStatus(status)}
                        </button>
                    ))}
                </div>
            </div>
        )}
      </div>

      {/* Main Content */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-6">
            {/* Comments / Interactions */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col h-[600px]">
                <div className="p-4 border-b border-gray-200 bg-gray-50 flex items-center justify-between">
                    <h3 className="font-bold text-gray-800 flex items-center">
                        <MessageSquare size={18} className="mr-2 text-gray-500" />
                        Interações
                    </h3>
                    <span className="text-xs text-gray-500">{comments.length} mensagens</span>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/30">
                    {comments.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-gray-400 text-sm">
                            <MessageSquare size={48} className="mb-2 opacity-20" />
                            <p>Nenhuma interação registrada ainda.</p>
                            <p>Inicie a conversa abaixo.</p>
                        </div>
                    ) : (
                        comments.map((comment) => {
                            const isMe = comment.userId === currentUser.id;
                            const isStaff = comment.userRole === 'ADMIN';
                            return (
                                <div key={comment.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                    <div className={`max-w-[80%] ${isMe ? 'order-1' : 'order-2'}`}>
                                        <div className={`flex items-center text-xs text-gray-500 mb-1 ${isMe ? 'justify-end' : 'justify-start'}`}>
                                            <span className="font-medium mr-2">{comment.userName}</span>
                                            {isStaff && <span className="bg-orange-100 text-orange-700 px-1.5 py-0.5 rounded-sm text-[10px] mr-2">STAFF</span>}
                                            <span>{comment.createdAt.toLocaleString('pt-BR')}</span>
                                        </div>
                                        <div className={`p-3 rounded-2xl text-sm ${
                                            isMe 
                                            ? 'bg-primary-600 text-white rounded-tr-none' 
                                            : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
                                        }`}>
                                            {comment.content}
                                        </div>
                                    </div>
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold text-white flex-shrink-0 mt-5 ${
                                        isMe 
                                        ? 'bg-primary-400 order-2 ml-2' 
                                        : 'bg-gray-400 order-1 mr-2'
                                    }`}>
                                        {comment.userName.charAt(0).toUpperCase()}
                                    </div>
                                </div>
                            );
                        })
                    )}
                    <div ref={commentsEndRef} />
                </div>

                <div className="p-4 bg-white border-t border-gray-200">
                    <form onSubmit={handleSendComment} className="flex gap-2">
                        <input
                            type="text"
                            value={newComment}
                            onChange={(e) => setNewComment(e.target.value)}
                            placeholder="Escreva uma mensagem..."
                            className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none"
                        />
                        <button 
                            type="submit" 
                            disabled={!newComment.trim()}
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            <Send size={18} />
                        </button>
                    </form>
                </div>
            </div>
          </div>

          <div className="space-y-6">
             {/* Real Audit History */}
             <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6">
                 <h3 className="font-bold text-gray-900 mb-4 text-sm uppercase tracking-wide">Histórico do Chamado</h3>
                 <div className="space-y-6">
                    {logs.length === 0 ? (
                         <div className="flex items-center space-x-3 opacity-50">
                             <div className="h-2 w-2 rounded-full bg-gray-400"></div>
                             <div>
                                 <p className="text-sm font-medium text-gray-900">Chamado Criado</p>
                                 <p className="text-xs text-gray-500">{ticket.createdAt.toLocaleString('pt-BR')}</p>
                             </div>
                         </div>
                    ) : (
                        logs.map((log, index) => (
                            <div key={log.id} className="relative flex gap-3">
                                {/* Timeline line connector */}
                                {index !== logs.length - 1 && (
                                    <div className="absolute top-6 left-[5px] h-full w-[2px] bg-gray-100"></div>
                                )}

                                <div className="mt-1 flex-shrink-0">
                                    <div className="bg-white relative z-10">
                                        {getLogIcon(log.action)}
                                    </div>
                                </div>
                                <div>
                                    <p className="text-sm font-medium text-gray-900">{translateLogAction(log.action)}</p>
                                    <p className="text-xs text-gray-500 mb-1">
                                        por <span className="font-medium text-gray-700">{log.actorName}</span> • {log.createdAt.toLocaleString('pt-BR')}
                                    </p>
                                    {log.details && (
                                        <p className="text-xs text-gray-600 bg-gray-50 p-2 rounded border border-gray-100 inline-block mt-1">
                                            {log.details}
                                        </p>
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                 </div>
             </div>
          </div>
      </div>
    </div>
  );
};

