import React, { useState, useEffect } from 'react';
import { Ticket, TicketPriority, TicketStatus, User } from '../types';
import { Loader2, ArrowLeft, Paperclip, X, FileText, Check, User as UserIcon } from 'lucide-react';
import { supabase } from '../services/supabase';
import { v4 as uuidv4 } from 'uuid';

interface TicketFormProps {
  onSave: (ticket: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => void;
  onCancel: () => void;
  initialData?: Ticket; // Optional for Edit mode
  currentUser: User; // Obrigatório para pegar o nome automaticamente
}

const CATEGORIES = [
  'ERP MEGA',
  'Microgestão',
  'Power BI',
  'Acessos',
  'Outro'
];

export const TicketForm: React.FC<TicketFormProps> = ({ onSave, onCancel, initialData, currentUser }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<TicketPriority>(TicketPriority.LOW);
  const [category, setCategory] = useState(CATEGORIES[0]);

  // Requester Selection State
  const [requesterId, setRequesterId] = useState(currentUser.id);
  const [requesterName, setRequesterName] = useState(currentUser.name);
  const [availableUsers, setAvailableUsers] = useState<{id: string, name: string}[]>([]);

  // Attachments State
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  useEffect(() => {
    // If Admin, fetch all users to allow changing the requester
    if (currentUser.role === 'ADMIN') {
        fetchUsers();
    }
  }, [currentUser.role]);

  useEffect(() => {
    if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPriority(initialData.priority);
        setCategory(initialData.category);
        setAttachments(initialData.attachments || []);
        setRequesterId(initialData.requesterId);
        setRequesterName(initialData.requester);
    } else {
        // Reset to current user if creating new
        setRequesterId(currentUser.id);
        setRequesterName(currentUser.name);
    }
  }, [initialData, currentUser]);

  const fetchUsers = async () => {
      const { data } = await supabase.from('profiles').select('id, name').order('name');
      if (data) {
          setAvailableUsers(data);
      }
  };

  const handleRequesterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const selectedId = e.target.value;
      setRequesterId(selectedId);
      const selectedUser = availableUsers.find(u => u.id === selectedId);
      if (selectedUser) {
          setRequesterName(selectedUser.name);
      }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!e.target.files || e.target.files.length === 0) return;

      setIsUploading(true);
      setUploadProgress(0);

      const file = e.target.files[0];
      const fileExt = file.name.split('.').pop();
      // Adiciona timestamp para evitar conflitos de nome
      const fileName = `${Date.now()}_${uuidv4()}.${fileExt}`;
      const filePath = `${currentUser.id}/${fileName}`;

      // Simulação de progresso visual (já que o supabase upload simples não tem callback de progresso nativo exposto facilmente)
      const progressInterval = setInterval(() => {
        setUploadProgress((prev) => {
            if (prev >= 90) return prev; // Segura em 90% até terminar
            return prev + 10;
        });
      }, 100);

      try {
          const { error: uploadError } = await supabase.storage
            .from('attachments')
            .upload(filePath, file);

          if (uploadError) throw uploadError;

          // Upload concluído
          clearInterval(progressInterval);
          setUploadProgress(100);

          const { data } = supabase.storage.from('attachments').getPublicUrl(filePath);

          if (data) {
              // Pequeno delay para o usuário ver o 100%
              setTimeout(() => {
                  setAttachments(prev => [...prev, data.publicUrl]);
                  setIsUploading(false);
                  setUploadProgress(0);
              }, 500);
          } else {
              setIsUploading(false);
          }
      } catch (error: any) {
          console.error('Error uploading file:', error);
          alert(`Erro ao fazer upload: ${error.message || 'Verifique as permissões do Bucket.'}`);
          setIsUploading(false);
          setUploadProgress(0);
      } finally {
          clearInterval(progressInterval);
          // Reset input para permitir selecionar o mesmo arquivo se der erro
          e.target.value = ''; 
      }
  };

  const removeAttachment = (urlToRemove: string) => {
      setAttachments(prev => prev.filter(url => url !== urlToRemove));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      title,
      description,
      requester: requesterName, 
      requesterId: requesterId, 
      priority,
      category,
      status: initialData ? initialData.status : TicketStatus.OPEN,
      attachments: attachments
    });
  };

  // Configuração visual dos cartões de prioridade
  const PRIORITY_OPTIONS = [
    { 
        id: TicketPriority.LOW, 
        label: 'Baixa', 
        colorClass: 'hover:border-green-400 hover:bg-green-50', 
        selectedClass: 'border-green-500 bg-green-50 text-green-700 ring-1 ring-green-500',
        desc: 'Dúvidas ou solicitações simples' 
    },
    { 
        id: TicketPriority.MEDIUM, 
        label: 'Média', 
        colorClass: 'hover:border-yellow-400 hover:bg-yellow-50', 
        selectedClass: 'border-yellow-500 bg-yellow-50 text-yellow-800 ring-1 ring-yellow-500',
        desc: 'Problemas que afetam o trabalho' 
    },
    { 
        id: TicketPriority.HIGH, 
        label: 'Alta', 
        colorClass: 'hover:border-orange-400 hover:bg-orange-50', 
        selectedClass: 'border-orange-500 bg-orange-50 text-orange-800 ring-1 ring-orange-500',
        desc: 'Urgente, impede funções críticas' 
    },
    { 
        id: TicketPriority.CRITICAL, 
        label: 'Crítica', 
        colorClass: 'hover:border-red-400 hover:bg-red-50', 
        selectedClass: 'border-red-500 bg-red-50 text-red-800 ring-1 ring-red-500',
        desc: 'Sistema parado ou emergência' 
    }
  ];

  return (
    <div className="max-w-4xl mx-auto">
      <button onClick={onCancel} className="flex items-center text-gray-500 hover:text-gray-700 mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" />
        Voltar para lista
      </button>

      <div className="bg-white rounded-xl border border-gray-200 shadow-xl overflow-hidden">
        {/* Cabeçalho Visual */}
        <div className="p-6 border-b border-gray-200 bg-gradient-to-r from-primary-600 to-primary-800 text-white">
          <div className="flex justify-between items-center">
             <div>
                <h2 className="text-xl font-bold">{initialData ? 'Editar Chamado' : 'Abrir Novo Chamado'}</h2>
                <p className="text-primary-100 text-sm mt-1 opacity-90">Descreva o problema para que possamos ajudar rapidamente.</p>
             </div>
             <div className="hidden md:block bg-white/10 p-3 rounded-lg backdrop-blur-sm">
                <FileText size={24} className="text-white" />
             </div>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">

          {/* Seção 1: Informações Básicas */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Solicitante</label>
                    {currentUser.role === 'ADMIN' ? (
                        <div className="relative">
                            <select
                                value={requesterId}
                                onChange={handleRequesterChange}
                                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white appearance-none cursor-pointer hover:border-primary-400 transition-colors"
                            >
                                {availableUsers.map(user => (
                                    <option key={user.id} value={user.id}>{user.name}</option>
                                ))}
                            </select>
                            <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                                <UserIcon size={16} className="text-gray-400" />
                            </div>
                        </div>
                    ) : (
                        <input
                            type="text"
                            value={currentUser.name}
                            disabled
                            className="w-full px-4 py-2.5 border border-gray-200 rounded-lg bg-gray-50 text-gray-500 cursor-not-allowed font-medium"
                        />
                    )}
                    {currentUser.role === 'ADMIN' && (
                        <p className="text-xs text-gray-500 mt-1">Como Admin, você pode abrir chamados em nome de outros.</p>
                    )}
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Categoria</label>
                    <div className="relative">
                        <select
                            value={category}
                            onChange={(e) => setCategory(e.target.value)}
                            className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white appearance-none cursor-pointer hover:border-primary-400 transition-colors"
                        >
                            {CATEGORIES.map(cat => (
                                <option key={cat} value={cat}>{cat}</option>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                            <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                        </div>
                    </div>
                </div>
             </div>

             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Assunto</label>
                    <input
                        type="text"
                        required
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all placeholder-gray-400"
                        placeholder="Ex: Erro ao acessar o ERP"
                    />
                </div>
             </div>
          </div>

          <div className="border-t border-gray-100 my-2"></div>

          {/* Seção 2: Detalhes e Prioridade */}
          <div className="space-y-6">
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Descrição Detalhada</label>
                <div className="relative">
                    <textarea
                        required
                        rows={6}
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all resize-none leading-relaxed"
                        placeholder="Descreva o que aconteceu, quais passos você seguiu e se apareceu alguma mensagem de erro..."
                    />
                    <div className="absolute bottom-3 right-3 text-xs text-gray-400 pointer-events-none">
                        Quanto mais detalhes, mais rápido resolvemos.
                    </div>
                </div>
             </div>

             <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">Defina a Prioridade</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3">
                    {PRIORITY_OPTIONS.map((option) => (
                        <button
                            key={option.id}
                            type="button"
                            onClick={() => setPriority(option.id)}
                            className={`
                                relative flex flex-col items-start p-3 rounded-xl border transition-all duration-200 text-left
                                ${priority === option.id ? option.selectedClass : 'border-gray-200 bg-white text-gray-600 ' + option.colorClass}
                            `}
                        >
                            <div className="flex items-center justify-between w-full mb-1">
                                <span className="font-bold text-sm">{option.label}</span>
                                {priority === option.id && <Check size={16} className="text-current" />}
                            </div>
                            <span className="text-xs opacity-80">{option.desc}</span>
                        </button>
                    ))}
                </div>
             </div>

             {/* Attachments Section Modernized */}
             <div className="bg-gray-50 rounded-lg p-4 border border-dashed border-gray-300">
                  <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                      <div>
                          <label className="block text-sm font-medium text-gray-700">Anexos (Opcional)</label>
                          <p className="text-xs text-gray-500 mt-1">Adicione prints ou documentos para ajudar.</p>
                      </div>

                      {/* Upload Button or Progress Bar */}
                      <label className={`
                          flex flex-col md:flex-row items-center justify-center space-x-0 md:space-x-2 px-4 py-2 rounded-lg transition-all shadow-sm w-full md:w-auto min-w-[160px] relative overflow-hidden
                          ${isUploading 
                            ? 'bg-gray-50 border border-gray-200 cursor-not-allowed h-12' 
                            : 'bg-white border border-gray-300 text-gray-700 hover:bg-gray-100 cursor-pointer h-10'}
                      `}>
                          {isUploading ? (
                              <div className="w-full px-2 flex flex-col justify-center h-full">
                                  <div className="flex justify-between items-center mb-1 w-full">
                                      <span className="text-xs font-semibold text-primary-700 flex items-center">
                                          <Loader2 size={10} className="animate-spin mr-1" />
                                          Enviando...
                                      </span>
                                      <span className="text-xs font-bold text-primary-700">{uploadProgress}%</span>
                                  </div>
                                  <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden">
                                      <div 
                                        className="bg-primary-600 h-1.5 rounded-full transition-all duration-300 ease-out" 
                                        style={{ width: `${uploadProgress}%` }}
                                      ></div>
                                  </div>
                              </div>
                          ) : (
                              <>
                                <Paperclip size={18} />
                                <span className="text-sm font-medium">Selecionar Arquivo</span>
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    onChange={handleFileUpload} 
                                    disabled={isUploading}
                                />
                              </>
                          )}
                      </label>
                  </div>

                  {attachments.length > 0 && (
                      <div className="mt-4 grid grid-cols-1 sm:grid-cols-2 gap-2">
                          {attachments.map((url, index) => (
                              <div key={index} className="flex items-center justify-between bg-white px-3 py-2 rounded border border-gray-200 shadow-sm animate-blob">
                                  <div className="flex items-center space-x-2 overflow-hidden">
                                      <div className="bg-blue-50 p-1.5 rounded text-blue-500">
                                        <FileText size={14} />
                                      </div>
                                      <a href={url} target="_blank" rel="noreferrer" className="text-xs font-medium text-gray-700 hover:text-blue-600 hover:underline truncate max-w-[150px]">
                                          Anexo {index + 1}
                                      </a>
                                  </div>
                                  <button 
                                    type="button" 
                                    onClick={() => removeAttachment(url)}
                                    className="text-gray-400 hover:text-red-500 p-1 rounded-full hover:bg-red-50 transition-colors"
                                  >
                                      <X size={14} />
                                  </button>
                              </div>
                          ))}
                      </div>
                  )}
             </div>
          </div>

          {/* Footer Actions */}
          <div className="pt-6 flex flex-col-reverse md:flex-row justify-end gap-3 md:gap-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-2.5 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 font-medium transition-colors w-full md:w-auto text-center"
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={isUploading}
              className={`px-8 py-2.5 text-white rounded-lg font-medium shadow-lg transition-all w-full md:w-auto text-center flex justify-center items-center
                ${isUploading 
                    ? 'bg-primary-400 cursor-not-allowed' 
                    : 'bg-primary-600 hover:bg-primary-700 hover:shadow-xl hover:-translate-y-0.5'}
              `}
            >
              {isUploading && <Loader2 size={18} className="animate-spin mr-2" />}
              {initialData ? 'Salvar Alterações' : 'Criar Chamado'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { TicketDetail } from './components/TicketDetail';
import { Login } from './components/Login';
import { UserManagement } from './components/UserManagement';
import { Notifications } from './components/Notifications';
import { Dashboard } from './components/Dashboard';
import { Ticket, ViewState, TicketStatus, User } from './types';
import { supabase } from './services/supabase';
import { Loader2, Menu } from 'lucide-react';
import { Logo } from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [ticketToEdit, setTicketToEdit] = useState<Ticket | null>(null);
  const [loading, setLoading] = useState(true);

  // Mobile Sidebar State
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Check auth session on load
  useEffect(() => {
    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            fetchProfile(session.user.id, session.user.email!);
        } else {
            setCurrentUser(null);
            setTickets([]);
            setLoading(false);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch tickets whenever user changes or view updates
  useEffect(() => {
      if (currentUser) {
          fetchTickets();
      }
  }, [currentUser, currentView]);

  const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
          await fetchProfile(session.user.id, session.user.email!);
      } else {
          setLoading(false);
      }
  };

  const fetchProfile = async (userId: string, email: string) => {
      try {
          // 1. Get Auth Metadata to ensure we have the real name entered during sign up
          const { data: authUser } = await supabase.auth.getUser();
          const metaName = authUser.user?.user_metadata?.full_name;

          // Fallback name logic: Metadata > Email
          const displayName = metaName || email.split('@')[0];

          // 2. Attempt to fetch profile from DB
          let { data, error } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', userId)
            .maybeSingle();

          // 3. SELF-HEALING: If profile is missing but Auth exists, create it now.
          if (!data) {
            console.log("Profile missing for authenticated user. Creating default 'USER' profile...");

            const { data: newProfile, error: createError } = await supabase
                .from('profiles')
                .insert([{ 
                    id: userId, 
                    email: email, 
                    name: displayName, // Uses the real name from registration if available
                    role: 'USER', // Enforced default role
                    is_active: true
                }])
                .select()
                .single();

            if (createError) {
                console.error("Failed to auto-create profile:", createError);
                throw createError;
            }
            data = newProfile;
          } else if (error) {
            throw error;
          }

          // 4. Check for INACTIVE status
          if (data.is_active === false) {
              alert("Sua conta foi desativada pelo administrador. Entre em contato com o suporte.");
              await supabase.auth.signOut();
              setCurrentUser(null);
              setLoading(false);
              return;
          }

          // 5. SPECIAL ADMIN OVERRIDE (Bootstrap)
          const superAdmins = ['ti@grupoairslaid.com.br'];
          if (superAdmins.includes(email) || email.startsWith('admin') || email.startsWith('dev')) {
             if (data && data.role !== 'ADMIN') {
                 console.log(`Promoting super user ${email} to ADMIN...`);
                 await supabase.from('profiles').update({ role: 'ADMIN' }).eq('id', userId);
                 data.role = 'ADMIN';
             }
          }

          if (data) {
            setCurrentUser({
                id: data.id,
                name: data.name, // Use DB name (which we ensured matches metadata on creation)
                email: data.email || email,
                role: data.role,
                isActive: data.is_active
            });
          }
      } catch (error) {
          console.error('Error fetching/creating profile:', error);
      } finally {
          setLoading(false);
      }
  };

  const fetchTickets = async () => {
      try {
          // Alterado para fazer JOIN com a tabela profiles e pegar o nome atualizado
          const { data, error } = await supabase
            .from('tickets')
            .select('*, profiles:requester_id(name)')
            .order('created_at', { ascending: false });

          if (error) throw error;

          const formattedTickets: Ticket[] = data.map((t: any) => ({
              id: t.id,
              ticketNumber: t.ticket_number || 0,
              title: t.title,
              description: t.description,
              // Usa o nome do perfil (atualizado) se existir, senão usa o nome gravado no ticket (backup)
              requester: t.profiles?.name || t.requester_name,
              requesterId: t.requester_id,
              priority: t.priority,
              status: t.status,
              category: t.category,
              createdAt: new Date(t.created_at),
              updatedAt: t.updated_at ? new Date(t.updated_at) : new Date(t.created_at),
              resolvedAt: t.resolved_at ? new Date(t.resolved_at) : undefined,
              attachments: t.attachments || []
          }));

          setTickets(formattedTickets);
      } catch (error) {
          console.error('Error fetching tickets:', error);
      }
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      setCurrentView('DASHBOARD');
  };

  const handleCreateTicket = async (newTicketData: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => {
    if (!currentUser) return;

    try {
        if (ticketToEdit) {
            // Update existing ticket
            // We allow updating title, description, priority, category, status, and attachments
            // AND potentially the requester if changed by admin
            const { error } = await supabase
                .from('tickets')
                .update({
                    title: newTicketData.title,
                    description: newTicketData.description,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: newTicketData.status,
                    attachments: newTicketData.attachments,
                    requester_id: newTicketData.requesterId, // Update Requester ID
                    requester_name: newTicketData.requester // Update Requester Name
                })
                .eq('id', ticketToEdit.id);

            if (error) throw error;

            // Audit Log for Edit
            await supabase.from('audit_logs').insert({
                ticket_id: ticketToEdit.id,
                actor_id: currentUser.id,
                action: 'EDITED',
                details: 'Detalhes do chamado editados'
            });

            setTicketToEdit(null);
        } else {
            // Create new ticket
            // ticket_number is generated automatically by Postgres
            // Uses the requester info passed from the form (which might differ from currentUser if Admin)
            const { data: newTicket, error } = await supabase
                .from('tickets')
                .insert([{
                    title: newTicketData.title,
                    description: newTicketData.description,
                    requester_name: newTicketData.requester, 
                    requester_id: newTicketData.requesterId,
                    priority: newTicketData.priority,
                    category: newTicketData.category,
                    status: 'OPEN',
                    attachments: newTicketData.attachments
                }])
                .select()
                .single();

            if (error) throw error;

            if (newTicket) {
                // Audit Log for Creation
                await supabase.from('audit_logs').insert({
                    ticket_id: newTicket.id,
                    actor_id: currentUser.id,
                    action: 'CREATED',
                    details: `Chamado criado com prioridade ${newTicketData.priority}`
                });

                // NOTIFICATION LOGIC: Notify all Admins
                const { data: admins } = await supabase.from('profiles').select('id').eq('role', 'ADMIN');
                if (admins && admins.length > 0) {
                    const notifications = admins.map(admin => ({
                        user_id: admin.id,
                        title: 'Novo Chamado Criado',
                        message: `${newTicketData.requester} abriu um novo chamado: ${newTicketData.title}`,
                        ticket_id: newTicket.id
                    }));
                    await supabase.from('notifications').insert(notifications);
                }

                // If Admin opened for someone else, notify that user
                if (newTicketData.requesterId !== currentUser.id) {
                     await supabase.from('notifications').insert({
                        user_id: newTicketData.requesterId,
                        title: 'Chamado Aberto para Você',
                        message: `Um administrador abriu o chamado #${newTicket.ticket_number} em seu nome.`,
                        ticket_id: newTicket.id
                    });
                }
            }
        }

        await fetchTickets(); // Refresh list

        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS'); // Return to list view after edit/create
        }
    } catch (error) {
        console.error("Error saving ticket:", error);
        alert("Falha ao salvar chamado. Por favor, tente novamente.");
    }
  };

  const handleSelectTicket = (ticket: Ticket) => {
    setSelectedTicket(ticket);
    setCurrentView('TICKET_DETAIL');
  };

  const handleSelectNotificationTicket = async (ticketId: string) => {
      // Find the ticket in the current list or fetch it
      const existing = tickets.find(t => t.id === ticketId);
      if (existing) {
          setSelectedTicket(existing);
          setCurrentView('TICKET_DETAIL');
      } else {
          // Fallback fetch if not loaded
          const { data } = await supabase.from('tickets').select('*, profiles:requester_id(name)').eq('id', ticketId).single();
          if (data) {
             const formatted: Ticket = {
                id: data.id,
                ticketNumber: data.ticket_number,
                title: data.title,
                description: data.description,
                requester: data.profiles?.name || data.requester_name,
                requesterId: data.requester_id,
                priority: data.priority,
                status: data.status,
                category: data.category,
                createdAt: new Date(data.created_at),
                updatedAt: data.updated_at ? new Date(data.updated_at) : new Date(data.created_at),
                resolvedAt: data.resolved_at ? new Date(data.resolved_at) : undefined,
                attachments: data.attachments || []
             };
             setSelectedTicket(formatted);
             setCurrentView('TICKET_DETAIL');
          }
      }
  };

  const handleDeleteTicket = async (id: string) => {
      try {
        const { error } = await supabase.from('tickets').delete().eq('id', id);
        if (error) throw error;

        setTickets(tickets.filter(t => t.id !== id));
        if (currentUser?.role === 'USER') {
            setCurrentView('MY_TICKETS');
        } else {
            setCurrentView('ALL_TICKETS');
        }
      } catch (error) {
          console.error("Error deleting ticket:", error);
          alert("Falha ao excluir chamado.");
      }
  };

  const handleEditTicket = (ticket: Ticket) => {
      setTicketToEdit(ticket);
      setCurrentView('EDIT_TICKET');
  };

  const handleUpdateStatus = async (id: string, status: TicketStatus) => {
    if (!currentUser) return;

    try {
        // Prepare update data
        const updates: any = { status };

        // Logic for Resolved Date
        if (status === TicketStatus.RESOLVED) {
            updates.resolved_at = new Date().toISOString();
        } else {
            // If reopening, maybe clear resolved_at? 
            // updates.resolved_at = null; // Optional: Uncomment if reopening should clear the date
        }

        const { error } = await supabase
            .from('tickets')
            .update(updates)
            .eq('id', id);

        if (error) throw error;

        // Audit Log for Status Change
        await supabase.from('audit_logs').insert({
            ticket_id: id,
            actor_id: currentUser.id,
            action: 'STATUS_CHANGE',
            details: `Status alterado para ${status}`
        });

        // Update local state immediately (Optimistic or Fetch)
        setTickets(prev => prev.map(t => {
            if (t.id === id) {
                return {
                    ...t,
                    status,
                    resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : t.resolvedAt,
                    updatedAt: new Date() // Optimistic update for Last Update
                };
            }
            return t;
        }));

        if (selectedTicket && selectedTicket.id === id) {
            const updatedTicket = { 
                ...selectedTicket, 
                status,
                resolvedAt: updates.resolved_at ? new Date(updates.resolved_at) : selectedTicket.resolvedAt,
                updatedAt: new Date()
            };
            setSelectedTicket(updatedTicket);

            // NOTIFICATION LOGIC: Notify the requester if status changes
            // If I am an admin changing a user's ticket
            if (currentUser.role === 'ADMIN') {
                const { data: profile } = await supabase.from('profiles').select('name').eq('id', currentUser.id).single();
                const adminName = profile?.name || 'Admin';

                // Don't notify if I am the requester too
                if (selectedTicket.requesterId !== currentUser.id) {
                    await supabase.from('notifications').insert({
                        user_id: selectedTicket.requesterId,
                        title: 'Status Atualizado',
                        message: `Seu chamado "${selectedTicket.title}" mudou para ${status} por ${adminName}.`,
                        ticket_id: id
                    });
                }
            }
        }
    } catch (error) {
        console.error("Error updating status:", error);
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (currentView) {
      case 'CREATE_TICKET':
      case 'EDIT_TICKET':
        return (
          <TicketForm 
            onSave={handleCreateTicket} 
            onCancel={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} 
            initialData={currentView === 'EDIT_TICKET' ? ticketToEdit || undefined : undefined}
            currentUser={currentUser}
          />
        );
      case 'TICKET_DETAIL':
        return selectedTicket ? (
          <TicketDetail 
            ticket={selectedTicket}
            currentUser={currentUser}
            onBack={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')}
            onUpdateStatus={handleUpdateStatus}
            onDelete={handleDeleteTicket}
            onEdit={handleEditTicket}
          />
        ) : (
           <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
           />
        );
      case 'USERS':
        return currentUser.role === 'ADMIN' ? <UserManagement currentUser={currentUser} /> : <div>Acesso Negado</div>;
      case 'NOTIFICATIONS':
        return <Notifications currentUser={currentUser} onSelectNotification={handleSelectNotificationTicket} />;
      case 'MY_TICKETS':
      case 'ALL_TICKETS':
        return (
            <TicketList 
                tickets={tickets} 
                onSelectTicket={handleSelectTicket} 
                onCreateTicket={() => setCurrentView('CREATE_TICKET')} 
                onUpdateStatus={handleUpdateStatus} 
            />
        );
      case 'DASHBOARD':
      default:
        return <Dashboard tickets={tickets} currentUser={currentUser} onCreateTicket={() => setCurrentView('CREATE_TICKET')} />;
    }
  };

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <Loader2 className="animate-spin text-primary-600" size={48} />
          </div>
      );
  }

  if (!currentUser) {
    return <Login onLoginSuccess={() => checkUser()} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        currentUser={currentUser} 
        tickets={tickets}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 w-full bg-white z-30 border-b border-gray-200 px-4 py-3 flex items-center justify-between">
          <div className="flex items-center space-x-3">
              <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="p-1 text-gray-600 hover:bg-gray-100 rounded-lg"
              >
                  <Menu size={24} />
              </button>
              <div className="flex items-center space-x-2">
                 <Logo className="h-8 w-auto" />
                 <span className="text-lg font-bold text-gray-800">AirService</span>
              </div>
          </div>
          <div className="h-8 w-8 rounded-full bg-primary-600 text-white flex items-center justify-center text-xs font-bold">
              {currentUser.name.charAt(0).toUpperCase()}
          </div>
      </div>

      <main className={`flex-1 p-4 md:p-8 overflow-y-auto h-screen transition-all duration-300 ${isSidebarOpen ? '' : 'ml-0'} md:ml-64 pt-20 md:pt-8`}>
        {/* Changed from max-w-6xl mx-auto to w-[95%] mx-auto to stretch the grid */}
        <div className="w-full md:w-[95%] mx-auto">
          <header className="mb-6 md:mb-8 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <h1 className="text-xl md:text-2xl font-bold text-gray-900">
                {currentView === 'DASHBOARD' && (currentUser.role === 'ADMIN' ? 'Visão Geral' : 'Dashboard')}
                {currentView === 'MY_TICKETS' && 'Meus Chamados'}
                {currentView === 'ALL_TICKETS' && 'Todos os Chamados'}
                {currentView === 'CREATE_TICKET' && 'Novo Chamado'}
                {currentView === 'EDIT_TICKET' && 'Editar Chamado'}
                {currentView === 'TICKET_DETAIL' && 'Detalhes do Chamado'}
                {currentView === 'USERS' && 'Gestão de Usuários'}
                {currentView === 'NOTIFICATIONS' && 'Central de Notificações'}
              </h1>
            </div>
            <div className="hidden md:flex items-center space-x-4">
                <button 
                    onClick={handleLogout}
                    className="text-sm text-gray-500 hover:text-gray-700 underline"
                >
                    Sair
                </button>
                <div className="h-10 w-10 rounded-full bg-gradient-to-r from-primary-500 to-orange-600 flex items-center justify-center text-white font-bold shadow-md">
                    {currentUser.name.charAt(0).toUpperCase()}
                </div>
            </div>
            {/* Mobile Logout (shown below header on mobile) */}
            <div className="md:hidden w-full flex justify-end">
                <button 
                    onClick={handleLogout}
                    className="text-sm text-gray-500 border border-gray-200 px-3 py-1 rounded-lg"
                >
                    Sair
                </button>
            </div>
          </header>
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo } from 'react';
import { LayoutDashboard, Users, Ticket as TicketIcon, List, Bell, X } from 'lucide-react';
import { ViewState, User, Ticket, TicketStatus } from '../types';
import { supabase } from '../services/supabase';
import { Logo } from './Logo';

interface SidebarProps {
  currentView: ViewState;
  onChangeView: (view: ViewState) => void;
  currentUser: User;
  tickets: Ticket[]; // Added missing prop
  isOpen: boolean;
  onClose: () => void;
}

interface NavItem {
  id: string;
  label: string;
  icon: React.ElementType;
  badge?: number;
}

export const Sidebar: React.FC<SidebarProps> = ({ currentView, onChangeView, currentUser, tickets, isOpen, onClose }) => {
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    fetchUnreadNotifications();

    // Realtime subscription for notifications
    const channel = supabase
      .channel('public:notifications')
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'notifications', 
        filter: `user_id=eq.${currentUser.id}` 
      }, () => {
        fetchUnreadNotifications();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    }
  }, [currentUser.id]);

  const fetchUnreadNotifications = async () => {
    const { count } = await supabase
      .from('notifications')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', currentUser.id)
      .eq('is_read', false);

    setUnreadCount(count || 0);
  };

  // Calculate Stats based on User Role
  const stats = useMemo(() => {
    // If Admin, count all relevant status tickets. If User, only theirs.
    const userTickets = currentUser.role === 'ADMIN' 
        ? tickets 
        : tickets.filter(t => t.requesterId === currentUser.id);

    return {
      open: userTickets.filter(t => t.status === TicketStatus.OPEN).length,
      inProgress: userTickets.filter(t => t.status === TicketStatus.IN_PROGRESS).length
    };
  }, [tickets, currentUser]);

  const getNavItems = (): NavItem[] => {
    const commonItems: NavItem[] = [
      { id: 'NOTIFICATIONS', label: 'Notificações', icon: Bell, badge: unreadCount },
    ];

    if (currentUser.role === 'USER') {
      return [
        { id: 'DASHBOARD', label: 'Visão Geral', icon: LayoutDashboard },
        ...commonItems,
        { id: 'MY_TICKETS', label: 'Meus Chamados', icon: List },
      ];
    }

    return [
      { id: 'DASHBOARD', label: 'Dashboard', icon: LayoutDashboard },
      ...commonItems,
      { id: 'ALL_TICKETS', label: 'Todos os Chamados', icon: TicketIcon },
      { id: 'USERS', label: 'Gestão de Usuários', icon: Users },
    ];
  };

  const navItems = getNavItems();

  const handleItemClick = (view: ViewState) => {
      onChangeView(view);
      onClose();
  };

  return (
    <>
        <div className={`
            fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-screen
            transform transition-transform duration-300 ease-in-out
            ${isOpen ? 'translate-x-0' : '-translate-x-full'} 
            md:translate-x-0
        `}>
        <div className="p-6 flex items-center justify-between border-b border-gray-100 h-20">
            <div className="flex items-center space-x-2">
                <Logo className="h-10 w-auto" />
                <span className="text-xl font-bold text-gray-800 tracking-tight">AirService</span>
            </div>
            <button onClick={onClose} className="md:hidden text-gray-500 hover:text-gray-700">
                <X size={24} />
            </button>
        </div>

        <div className="px-6 py-4">
            <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 shadow-sm">
                <div className="flex items-center space-x-3 mb-3">
                    <div className="h-9 w-9 rounded-full bg-primary-100 text-primary-600 flex items-center justify-center font-bold text-sm ring-2 ring-white">
                        {currentUser.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="overflow-hidden">
                        <p className="text-sm font-semibold text-gray-900 truncate">{currentUser.name}</p>
                        <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 truncate">
                            {currentUser.role === 'ADMIN' ? 'Desenvolvedor/Admin' : 'Usuário'}
                        </p>
                    </div>
                </div>

                {/* Status Summary */}
                <div className="grid grid-cols-2 gap-2 mt-3">
                    <div className="bg-white p-2 rounded-lg border border-yellow-100 flex flex-col items-center">
                        <span className="text-sm font-bold text-yellow-700">{stats.open}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Abertos</span>
                    </div>
                    <div className="bg-white p-2 rounded-lg border border-blue-100 flex flex-col items-center">
                        <span className="text-sm font-bold text-blue-700">{stats.inProgress}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Em And.</span>
                    </div>
                </div>
            </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            {navItems.map((item) => {
                const Icon = item.icon;
                let isActive = currentView === item.id;

                if (['TICKET_DETAIL', 'CREATE_TICKET', 'EDIT_TICKET'].includes(currentView)) {
                    if (currentUser.role === 'ADMIN' && item.id === 'ALL_TICKETS') isActive = true;
                    if (currentUser.role === 'USER' && item.id === 'MY_TICKETS') isActive = true;
                }

                return (
                    <button
                    key={item.id + item.label}
                    onClick={() => handleItemClick(item.id as ViewState)}
                    className={`w-full flex items-center justify-between px-4 py-3 rounded-lg text-sm font-medium transition-colors duration-200 ${
                        isActive
                        ? 'bg-primary-50 text-primary-700'
                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                    }`}
                    >
                    <div className="flex items-center space-x-3">
                        <Icon size={20} />
                        <span>{item.label}</span>
                    </div>
                    {item.badge ? (
                        <span className="bg-red-500 text-white text-xs font-bold px-2 py-0.5 rounded-full">
                        {item.badge}
                        </span>
                    ) : null}
                    </button>
                );
            })}
        </nav>
        </div>

        {isOpen && (
            <div 
                className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden"
                onClick={onClose}
            ></div>
        )}
    </>
  );
};

