  return (
    <>
        <div className={`
            fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-screen
            transform transition-transform duration-300 ease-in-out
            ${isOpen ? 'translate-x-0' : '-translate-x-full'} 
            md:translate-x-0
        `}>
        <div className="p-6 flex items-center justify-between border-b border-gray-100 h-20">
            <div className="flex items-center space-x-2">
                <Logo className="h-10 w-auto" />
                <span className="text-xl font-bold text-gray-800 tracking-tight">AirService</span>
            </div>
            <button onClick={onClose} className="md:hidden text-gray-500 hover:text-gray-700">
                <X size={24} />
            </button>
        </div>

        <div className="px-6 py-4">
            <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 shadow-sm">
                <div className="flex items-center space-x-3 mb-3">
                    <div className="h-9 w-9 rounded-full bg-primary-600 text-white flex items-center justify-center font-bold text-sm ring-2 ring-white">
                        {currentUser.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="overflow-hidden">
                        <p className="text-sm font-semibold text-gray-900 truncate">{currentUser.name}</p>
                        <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 truncate">
                            {currentUser.role === 'ADMIN' ? 'Desenvolvedor/Admin' : 'Usuário'}
                        </p>
                    </div>
                </div>

                {/* Resumo de Status solicitado */}
                <div className="grid grid-cols-2 gap-2 mt-2">
                    <div className="bg-white p-2 rounded-lg border border-yellow-100 flex flex-col items-center justify-center">
                        <span className="text-sm font-bold text-yellow-700">{stats.open}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Abertos</span>
                    </div>
                    <div className="bg-white p-2 rounded-lg border border-blue-100 flex flex-col items-center justify-center">
                        <span className="text-sm font-bold text-blue-700">{stats.inProgress}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Em And.</span>
                    </div>
                </div>
            </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            {navItems.map((item) => {
                const Icon = item.icon;
                let isActive = currentView === item.id;

                if (['TICKET_DETAIL', 'CREATE_TICKET', 'EDIT_TICKET'].includes(currentView)) {
                    if (currentUser.role === 'ADMIN' && item.id === 'ALL_TICKETS') isActive = true;
                    if (currentUser.role === 'USER' && item.id === 'MY_TICKETS') isActive = true;
                }

                return (
                    <button
                    key={item.id + item.label}
                    onClick={() => handleItemClick(item.id as ViewState)}
                    className={`w-full flex items-center justify-between px-4 py-3 rounded-lg text-sm font-medium transition-colors duration-200 ${
                        isActive
                        ? 'bg-primary-50 text-primary-700'
                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                    }`}
                    >
                    <div className="flex items-center space-x-3">
                        <Icon size={20} />
                        <span>{item.label}</span>
                    </div>
                    {item.badge ? (
                        <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">
                        {item.badge}
                        </span>
                    ) : null}
                    </button>
                );
            })}
        </nav>
        </div>

        {isOpen && (
            <div 
                className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden"
                onClick={onClose}
            ></div>
        )}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Ticket, TicketPriority, TicketStatus, User } from '../types';
import { Loader2, ArrowLeft, Paperclip, X, FileText, Check, User as UserIcon } from 'lucide-react';
import { supabase } from '../services/supabase';
import { v4 as uuidv4 } from 'uuid';

interface TicketFormProps {
  onSave: (ticket: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => void;
  onCancel: () => void;
  initialData?: Ticket;
  currentUser: User;
}

const CATEGORIES = [
  'ERP MEGA',
  'Microgestão',
  'Power BI',
  'Acessos',
  'Outro'
];

export const TicketForm: React.FC<TicketFormProps> = ({ onSave, onCancel, initialData, currentUser }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<TicketPriority>(TicketPriority.LOW);
  const [category, setCategory] = useState(CATEGORIES[0]);

  // Requester Selection State
  const [requesterId, setRequesterId] = useState(currentUser.id);
  const [requesterName, setRequesterName] = useState(currentUser.name);
  const [availableUsers, setAvailableUsers] = useState<{id: string, name: string}[]>([]);

  // Attachments State
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  useEffect(() => {
    if (currentUser.role === 'ADMIN') {
        fetchUsers();
    }
  }, [currentUser.role]);

  useEffect(() => {
    if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPriority(initialData.priority);
        setCategory(initialData.category);
        setAttachments(initialData.attachments || []);
        setRequesterId(initialData.requesterId);
        setRequesterName(initialData.requester);
    }
  }, [initialData]);

  const fetchUsers = async () => {
      const { data } = await supabase.from('profiles').select('id, name').eq('is_active', true).order('name');
      if (data) {
          setAvailableUsers(data);
      }
  };

  const handleRequesterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const selectedId = e.target.value;
      setRequesterId(selectedId);
      const selectedUser = availableUsers.find(u => u.id === selectedId);
      if (selectedUser) {
          setRequesterName(selectedUser.name);
      }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!e.target.files || e.target.files.length === 0) return;
      setIsUploading(true);
      setUploadProgress(10);

      const file = e.target.files[0];
      const fileName = `${Date.now()}_${uuidv4()}.${file.name.split('.').pop()}`;
      const filePath = `${currentUser.id}/${fileName}`;

      try {
          const { error: uploadError } = await supabase.storage.from('attachments').upload(filePath, file);
          if (uploadError) throw uploadError;
          setUploadProgress(100);

          const { data } = supabase.storage.from('attachments').getPublicUrl(filePath);
          if (data) {
              setAttachments(prev => [...prev, data.publicUrl]);
          }
      } catch (error: any) {
          alert(`Erro no upload: ${error.message}`);
      } finally {
          setIsUploading(false);
          setUploadProgress(0);
          e.target.value = '';
      }
  };

  const removeAttachment = (urlToRemove: string) => {
      setAttachments(prev => prev.filter(url => url !== urlToRemove));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      title,
      description,
      requester: requesterName, 
      requesterId: requesterId, 
      priority,
      category,
      status: initialData ? initialData.status : TicketStatus.OPEN,
      attachments: attachments
    });
  };

  const PRIORITY_OPTIONS = [
    { id: TicketPriority.LOW, label: 'Baixa', colorClass: 'hover:border-green-400', selectedClass: 'border-green-500 bg-green-50 text-green-700', desc: 'Dúvidas simples' },
    { id: TicketPriority.MEDIUM, label: 'Média', colorClass: 'hover:border-yellow-400', selectedClass: 'border-yellow-500 bg-yellow-50 text-yellow-800', desc: 'Afeta o trabalho' },
    { id: TicketPriority.HIGH, label: 'Alta', colorClass: 'hover:border-orange-400', selectedClass: 'border-orange-500 bg-orange-50 text-orange-800', desc: 'Urgente' },
    { id: TicketPriority.CRITICAL, label: 'Crítica', colorClass: 'hover:border-red-400', selectedClass: 'border-red-500 bg-red-50 text-red-800', desc: 'Parada crítica' }
  ];

  return (
    <div className="max-w-4xl mx-auto">
      <button onClick={onCancel} className="flex items-center text-gray-500 hover:text-gray-700 mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" />
        Voltar para lista
      </button>

      <div className="bg-white rounded-xl border border-gray-200 shadow-xl overflow-hidden">
        <div className="p-6 border-b border-gray-200 bg-gradient-to-r from-primary-600 to-primary-800 text-white">
          <h2 className="text-xl font-bold">{initialData ? 'Editar Chamado' : 'Abrir Novo Chamado'}</h2>
          <p className="text-primary-100 text-sm mt-1 opacity-90">Preencha os detalhes para suporte.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Solicitante</label>
                    {currentUser.role === 'ADMIN' ? (
                        <div className="relative">
                            <select
                                value={requesterId}
                                onChange={handleRequesterChange}
                                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white appearance-none cursor-pointer"
                            >
                                {availableUsers.map(user => (
                                    <option key={user.id} value={user.id}>{user.name}</option>
                                ))}
                            </select>
                            <UserIcon size={16} className="absolute right-3 top-3 text-gray-400 pointer-events-none" />
                        </div>
                    ) : (
                        <input type="text" value={currentUser.name} disabled className="w-full px-4 py-2.5 border border-gray-200 rounded-lg bg-gray-50 text-gray-500 cursor-not-allowed" />
                    )}
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Categoria</label>
                    <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none">
                        {CATEGORIES.map(cat => (
                            <option key={cat} value={cat}>{cat}</option>
                        ))}
                    </select>
                </div>
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Assunto</label>
                <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none" placeholder="Ex: Erro no acesso ao ERP" />
             </div>
          </div>

          <div className="space-y-6">
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Descrição</label>
                <textarea required rows={5} value={description} onChange={(e) => setDescription(e.target.value)} className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none resize-none" />
             </div>

             <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">Prioridade</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3">
                    {PRIORITY_OPTIONS.map((opt) => (
                        <button key={opt.id} type="button" onClick={() => setPriority(opt.id)} className={`flex flex-col p-3 rounded-xl border text-left transition-all ${priority === opt.id ? opt.selectedClass : 'bg-white text-gray-600 border-gray-200 ' + opt.colorClass}`}>
                            <span className="font-bold text-sm">{opt.label}</span>
                            <span className="text-[10px] opacity-80">{opt.desc}</span>
                        </button>
                    ))}
                </div>
             </div>
          </div>

          <div className="pt-6 flex justify-end gap-3 border-t border-gray-100">
            <button type="button" onClick={onCancel} className="px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50">Cancelar</button>
            <button type="submit" disabled={isUploading} className="px-8 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 shadow-md flex items-center">
              {isUploading && <Loader2 size={18} className="animate-spin mr-2" />}
              {initialData ? 'Salvar' : 'Criar Chamado'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { TicketDetail } from './components/TicketDetail';
import { Login } from './components/Login';
import { UserManagement } from './components/UserManagement';
import { Notifications } from './components/Notifications';
import { Dashboard } from './components/Dashboard';
import { Ticket, ViewState, TicketStatus, User } from './types';
import { supabase } from './services/supabase';
import { Loader2, Menu } from 'lucide-react';
import { Logo } from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [ticketToEdit, setTicketToEdit] = useState<Ticket | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    checkUser();
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) fetchProfile(session.user.id, session.user.email!);
        else { setCurrentUser(null); setTickets([]); setLoading(false); }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
      if (currentUser) fetchTickets();
  }, [currentUser, currentView]);

  const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) await fetchProfile(session.user.id, session.user.email!);
      else setLoading(false);
  };

  const fetchProfile = async (userId: string, email: string) => {
      try {
          const { data } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
          if (data && data.is_active !== false) {
            setCurrentUser({ id: data.id, name: data.name, email: data.email || email, role: data.role, isActive: data.is_active });
          } else if (data && data.is_active === false) {
            alert("Conta desativada."); await supabase.auth.signOut();
          }
      } catch (error) { console.error('Error profile:', error); } finally { setLoading(false); }
  };

  const fetchTickets = async () => {
      try {
          const { data, error } = await supabase.from('tickets').select('*, profiles:requester_id(name)').order('created_at', { ascending: false });
          if (error) throw error;
          setTickets(data.map((t: any) => ({
              id: t.id, ticketNumber: t.ticket_number || 0, title: t.title, description: t.description,
              requester: t.profiles?.name || t.requester_name, requesterId: t.requester_id,
              priority: t.priority, status: t.status, category: t.category,
              createdAt: new Date(t.created_at), updatedAt: t.updated_at ? new Date(t.updated_at) : new Date(t.created_at),
              resolvedAt: t.resolved_at ? new Date(t.resolved_at) : undefined, attachments: t.attachments || []
          })));
      } catch (error) { console.error('Error tickets:', error); }
  };

  const handleCreateTicket = async (newTicketData: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => {
    if (!currentUser) return;
    try {
        const { data, error } = await supabase.from('tickets').insert([{
            title: newTicketData.title, description: newTicketData.description,
            requester_name: newTicketData.requester, requester_id: newTicketData.requesterId,
            priority: newTicketData.priority, category: newTicketData.category,
            status: 'OPEN', attachments: newTicketData.attachments
        }]).select().single();
        if (error) throw error;
        await fetchTickets();
        setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS');
    } catch (error) { console.error("Error saving:", error); }
  };

  const handleUpdateStatus = async (id: string, status: TicketStatus) => {
    try {
        const { error } = await supabase.from('tickets').update({ status, resolved_at: status === TicketStatus.RESOLVED ? new Date().toISOString() : null }).eq('id', id);
        if (error) throw error;
        await fetchTickets();
    } catch (error) { console.error("Error status:", error); }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (currentView) {
      case 'CREATE_TICKET':
      case 'EDIT_TICKET':
        return <TicketForm onSave={handleCreateTicket} onCancel={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} initialData={currentView === 'EDIT_TICKET' ? ticketToEdit || undefined : undefined} currentUser={currentUser} />;
      case 'TICKET_DETAIL':
        return selectedTicket ? <TicketDetail ticket={selectedTicket} currentUser={currentUser} onBack={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} onUpdateStatus={handleUpdateStatus} onDelete={() => {}} onEdit={() => {}} /> : null;
      case 'USERS':
        return <UserManagement currentUser={currentUser} />;
      case 'NOTIFICATIONS':
        return <Notifications currentUser={currentUser} onSelectNotification={() => {}} />;
      case 'MY_TICKETS':
      case 'ALL_TICKETS':
        return <TicketList tickets={tickets} onSelectTicket={(t) => { setSelectedTicket(t); setCurrentView('TICKET_DETAIL'); }} onCreateTicket={() => setCurrentView('CREATE_TICKET')} onUpdateStatus={handleUpdateStatus} />;
      default:
        return <Dashboard tickets={tickets} currentUser={currentUser} onCreateTicket={() => setCurrentView('CREATE_TICKET')} />;
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin text-primary-600" size={48} /></div>;
  if (!currentUser) return <Login onLoginSuccess={() => checkUser()} />;

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar currentView={currentView} onChangeView={setCurrentView} currentUser={currentUser} tickets={tickets} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
      <main className="flex-1 transition-all duration-300 md:ml-64 p-4 md:p-8">
          <header className="mb-8 flex justify-between items-center">
              <div className="md:hidden flex items-center gap-2">
                <button onClick={() => setIsSidebarOpen(true)} className="p-2"><Menu /></button>
                <Logo className="h-8" />
              </div>
              <h1 className="text-2xl font-bold text-gray-900">AirService</h1>
              <button onClick={() => supabase.auth.signOut()} className="text-sm text-gray-500 hover:text-primary-600">Sair</button>
          </header>
          {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo } from 'react';
import { LayoutDashboard, Users, Ticket as TicketIcon, List, Bell, X } from 'lucide-react';
import { ViewState, User, Ticket, TicketStatus } from '../types';
import { supabase } from '../services/supabase';
import { Logo } from './Logo';

interface SidebarProps {
  currentView: ViewState;
  onChangeView: (view: ViewState) => void;
  currentUser: User;
  tickets: Ticket[]; // Adicionado para calcular o resumo
  isOpen: boolean;
  onClose: () => void;
}

interface NavItem {
  id: string;
  label: string;
  icon: React.ElementType;
  badge?: number;
}

export const Sidebar: React.FC<SidebarProps> = ({ currentView, onChangeView, currentUser, tickets, isOpen, onClose }) => {
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    fetchUnreadNotifications();

    const channel = supabase
      .channel('public:notifications')
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'notifications', 
        filter: `user_id=eq.${currentUser.id}` 
      }, () => {
        fetchUnreadNotifications();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    }
  }, [currentUser.id]);

  const fetchUnreadNotifications = async () => {
    const { count } = await supabase
      .from('notifications')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', currentUser.id)
      .eq('is_read', false);

    setUnreadCount(count || 0);
  };

  // Cálculo do Resumo de Status (Exibido na Sidebar conforme imagem)
  const stats = useMemo(() => {
    const userTickets = currentUser.role === 'ADMIN' 
        ? tickets 
        : tickets.filter(t => t.requesterId === currentUser.id);

    return {
      open: userTickets.filter(t => t.status === TicketStatus.OPEN).length,
      inProgress: userTickets.filter(t => t.status === TicketStatus.IN_PROGRESS).length
    };
  }, [tickets, currentUser]);

  const getNavItems = (): NavItem[] => {
    const commonItems: NavItem[] = [
      { id: 'NOTIFICATIONS', label: 'Notificações', icon: Bell, badge: unreadCount },
    ];

    if (currentUser.role === 'USER') {
      return [
        { id: 'DASHBOARD', label: 'Visão Geral', icon: LayoutDashboard },
        ...commonItems,
        { id: 'MY_TICKETS', label: 'Meus Chamados', icon: List },
      ];
    }

    return [
      { id: 'DASHBOARD', label: 'Dashboard', icon: LayoutDashboard },
      ...commonItems,
      { id: 'ALL_TICKETS', label: 'Todos os Chamados', icon: TicketIcon },
      { id: 'USERS', label: 'Gestão de Usuários', icon: Users },
    ];
  };

  const navItems = getNavItems();

  const handleItemClick = (view: ViewState) => {
      onChangeView(view);
      onClose();
  };

  return (
    <>
        <div className={`
            fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-200 flex flex-col h-screen
            transform transition-transform duration-300 ease-in-out
            ${isOpen ? 'translate-x-0' : '-translate-x-full'} 
            md:translate-x-0
        `}>
        <div className="p-6 flex items-center justify-between border-b border-gray-100 h-20">
            <div className="flex items-center space-x-2">
                <Logo className="h-10 w-auto" />
                <span className="text-xl font-bold text-gray-800 tracking-tight">AirService</span>
            </div>
            <button onClick={onClose} className="md:hidden text-gray-500 hover:text-gray-700">
                <X size={24} />
            </button>
        </div>

        <div className="px-6 py-4">
            <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 shadow-sm">
                <div className="flex items-center space-x-3 mb-4">
                    <div className="h-10 w-10 rounded-full bg-primary-600 text-white flex items-center justify-center font-bold text-sm ring-2 ring-white">
                        {currentUser.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="overflow-hidden">
                        <p className="text-sm font-semibold text-gray-900 truncate">{currentUser.name}</p>
                        <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 truncate">
                            {currentUser.role === 'ADMIN' ? 'Desenvolvedor/Admin' : 'Usuário'}
                        </p>
                    </div>
                </div>

                {/* Resumo de Status Visual */}
                <div className="grid grid-cols-2 gap-2 border-t border-gray-200 pt-3">
                    <div className="flex flex-col items-center">
                        <span className="text-sm font-bold text-yellow-600">{stats.open}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Abertos</span>
                    </div>
                    <div className="flex flex-col items-center border-l border-gray-200">
                        <span className="text-sm font-bold text-blue-600">{stats.inProgress}</span>
                        <span className="text-[9px] text-gray-400 uppercase font-bold">Andamento</span>
                    </div>
                </div>
            </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            {navItems.map((item) => {
                const Icon = item.icon;
                let isActive = currentView === item.id;

                if (['TICKET_DETAIL', 'CREATE_TICKET', 'EDIT_TICKET'].includes(currentView)) {
                    if (currentUser.role === 'ADMIN' && item.id === 'ALL_TICKETS') isActive = true;
                    if (currentUser.role === 'USER' && item.id === 'MY_TICKETS') isActive = true;
                }

                return (
                    <button
                    key={item.id + item.label}
                    onClick={() => handleItemClick(item.id as ViewState)}
                    className={`w-full flex items-center justify-between px-4 py-3 rounded-lg text-sm font-medium transition-colors duration-200 ${
                        isActive
                        ? 'bg-primary-50 text-primary-700'
                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                    }`}
                    >
                    <div className="flex items-center space-x-3">
                        <Icon size={20} />
                        <span>{item.label}</span>
                    </div>
                    {item.badge ? (
                        <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">
                        {item.badge}
                        </span>
                    ) : null}
                    </button>
                );
            })}
        </nav>
        </div>

        {isOpen && (
            <div 
                className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden"
                onClick={onClose}
            ></div>
        )}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Ticket, TicketPriority, TicketStatus, User } from '../types';
import { Loader2, ArrowLeft, Paperclip, X, FileText, Check, User as UserIcon } from 'lucide-react';
import { supabase } from '../services/supabase';
import { v4 as uuidv4 } from 'uuid';

interface TicketFormProps {
  onSave: (ticket: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => void;
  onCancel: () => void;
  initialData?: Ticket;
  currentUser: User;
}

const CATEGORIES = [
  'ERP MEGA',
  'Microgestão',
  'Power BI',
  'Acessos',
  'Outro'
];

export const TicketForm: React.FC<TicketFormProps> = ({ onSave, onCancel, initialData, currentUser }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<TicketPriority>(TicketPriority.LOW);
  const [category, setCategory] = useState(CATEGORIES[0]);

  // Estado para seleção de solicitante
  const [requesterId, setRequesterId] = useState(currentUser.id);
  const [requesterName, setRequesterName] = useState(currentUser.name);
  const [availableUsers, setAvailableUsers] = useState<{id: string, name: string}[]>([]);

  // Attachments State
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  useEffect(() => {
    // Busca usuários se for admin para permitir a troca
    if (currentUser.role === 'ADMIN') {
        fetchUsers();
    }
  }, [currentUser.role]);

  useEffect(() => {
    if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPriority(initialData.priority);
        setCategory(initialData.category);
        setAttachments(initialData.attachments || []);
        setRequesterId(initialData.requesterId);
        setRequesterName(initialData.requester);
    }
  }, [initialData]);

  const fetchUsers = async () => {
      const { data } = await supabase.from('profiles').select('id, name').eq('is_active', true).order('name');
      if (data) {
          setAvailableUsers(data);
      }
  };

  const handleRequesterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const selectedId = e.target.value;
      setRequesterId(selectedId);
      const selectedUser = availableUsers.find(u => u.id === selectedId);
      if (selectedUser) {
          setRequesterName(selectedUser.name);
      }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!e.target.files || e.target.files.length === 0) return;
      setIsUploading(true);
      setUploadProgress(0);

      const file = e.target.files[0];
      const fileName = `${Date.now()}_${uuidv4()}.${file.name.split('.').pop()}`;
      const filePath = `${currentUser.id}/${fileName}`;

      const progressInterval = setInterval(() => {
        setUploadProgress((prev) => (prev >= 90 ? prev : prev + 10));
      }, 100);

      try {
          const { error: uploadError } = await supabase.storage.from('attachments').upload(filePath, file);
          if (uploadError) throw uploadError;
          clearInterval(progressInterval);
          setUploadProgress(100);

          const { data } = supabase.storage.from('attachments').getPublicUrl(filePath);
          if (data) {
              setTimeout(() => {
                  setAttachments(prev => [...prev, data.publicUrl]);
                  setIsUploading(false);
              }, 500);
          }
      } catch (error: any) {
          alert(`Erro ao fazer upload: ${error.message}`);
          setIsUploading(false);
      } finally {
          clearInterval(progressInterval);
          e.target.value = ''; 
      }
  };

  const removeAttachment = (urlToRemove: string) => {
      setAttachments(prev => prev.filter(url => url !== urlToRemove));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      title,
      description,
      requester: requesterName, // Usa o nome selecionado
      requesterId: requesterId, // Usa o ID selecionado
      priority,
      category,
      status: initialData ? initialData.status : TicketStatus.OPEN,
      attachments: attachments
    });
  };

  const PRIORITY_OPTIONS = [
    { id: TicketPriority.LOW, label: 'Baixa', colorClass: 'hover:border-green-400', selectedClass: 'border-green-500 bg-green-50 text-green-700', desc: 'Dúvidas simples' },
    { id: TicketPriority.MEDIUM, label: 'Média', colorClass: 'hover:border-yellow-400', selectedClass: 'border-yellow-500 bg-yellow-50 text-yellow-800', desc: 'Afeta o trabalho' },
    { id: TicketPriority.HIGH, label: 'Alta', colorClass: 'hover:border-orange-400', selectedClass: 'border-orange-500 bg-orange-50 text-orange-800', desc: 'Urgente' },
    { id: TicketPriority.CRITICAL, label: 'Crítica', colorClass: 'hover:border-red-400', selectedClass: 'border-red-500 bg-red-50 text-red-800', desc: 'Sistema parado' }
  ];

  return (
    <div className="max-w-4xl mx-auto">
      <button onClick={onCancel} className="flex items-center text-gray-500 hover:text-gray-700 mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" />
        Voltar para lista
      </button>

      <div className="bg-white rounded-xl border border-gray-200 shadow-xl overflow-hidden">
        <div className="p-6 border-b border-gray-200 bg-gradient-to-r from-primary-600 to-primary-800 text-white">
          <h2 className="text-xl font-bold">{initialData ? 'Editar Chamado' : 'Abrir Novo Chamado'}</h2>
          <p className="text-primary-100 text-sm mt-1 opacity-90">Preencha os dados do atendimento.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Solicitante</label>
                    {currentUser.role === 'ADMIN' ? (
                        <div className="relative">
                            <select
                                value={requesterId}
                                onChange={handleRequesterChange}
                                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none bg-white appearance-none cursor-pointer"
                            >
                                {availableUsers.map(user => (
                                    <option key={user.id} value={user.id}>{user.name}</option>
                                ))}
                            </select>
                            <UserIcon size={16} className="absolute right-3 top-3.5 text-gray-400 pointer-events-none" />
                        </div>
                    ) : (
                        <input
                            type="text"
                            value={currentUser.name}
                            disabled
                            className="w-full px-4 py-2.5 border border-gray-200 rounded-lg bg-gray-50 text-gray-500 cursor-not-allowed font-medium"
                        />
                    )}
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Categoria</label>
                    <select
                        value={category}
                        onChange={(e) => setCategory(e.target.value)}
                        className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none"
                    >
                        {CATEGORIES.map(cat => (
                            <option key={cat} value={cat}>{cat}</option>
                        ))}
                    </select>
                </div>
             </div>

             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Assunto</label>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none"
                    placeholder="Ex: Erro ao acessar o ERP"
                />
             </div>
          </div>

          <div className="space-y-6">
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Descrição</label>
                <textarea
                    required
                    rows={5}
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none resize-none"
                />
             </div>

             <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">Prioridade</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3">
                    {PRIORITY_OPTIONS.map((option) => (
                        <button
                            key={option.id}
                            type="button"
                            onClick={() => setPriority(option.id)}
                            className={`flex flex-col p-3 rounded-xl border text-left transition-all ${priority === option.id ? option.selectedClass : 'bg-white text-gray-600 border-gray-200 ' + option.colorClass}`}
                        >
                            <span className="font-bold text-sm">{option.label}</span>
                            <span className="text-[10px] opacity-80">{option.desc}</span>
                        </button>
                    ))}
                </div>
             </div>
          </div>

          <div className="pt-6 flex justify-end gap-3 border-t border-gray-100">
            <button type="button" onClick={onCancel} className="px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50">Cancelar</button>
            <button type="submit" disabled={isUploading} className="px-8 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 shadow-md flex items-center">
              {isUploading && <Loader2 size={18} className="animate-spin mr-2" />}
              {initialData ? 'Salvar Alterações' : 'Criar Chamado'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { TicketDetail } from './components/TicketDetail';
import { Login } from './components/Login';
import { UserManagement } from './components/UserManagement';
import { Notifications } from './components/Notifications';
import { Dashboard } from './components/Dashboard';
import { Ticket, ViewState, TicketStatus, User } from './types';
import { supabase } from './services/supabase';
import { Loader2, Menu } from 'lucide-react';
import { Logo } from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
  const [ticketToEdit, setTicketToEdit] = useState<Ticket | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    checkUser();
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            fetchProfile(session.user.id, session.user.email!);
        } else {
            setCurrentUser(null);
            setTickets([]);
            setLoading(false);
        }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
      if (currentUser) {
          fetchTickets();
      }
  }, [currentUser, currentView]);

  const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
          await fetchProfile(session.user.id, session.user.email!);
      } else {
          setLoading(false);
      }
  };

  const fetchProfile = async (userId: string, email: string) => {
      try {
          const { data } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
          if (data && data.is_active !== false) {
            setCurrentUser({ id: data.id, name: data.name, email: data.email || email, role: data.role, isActive: data.is_active });
          } else if (data && data.is_active === false) {
            alert("Sua conta está desativada.");
            await supabase.auth.signOut();
          }
      } catch (error) {
          console.error('Error fetching profile:', error);
      } finally {
          setLoading(false);
      }
  };

  const fetchTickets = async () => {
      try {
          const { data, error } = await supabase
            .from('tickets')
            .select('*, profiles:requester_id(name)')
            .order('created_at', { ascending: false });

          if (error) throw error;

          setTickets(data.map((t: any) => ({
              id: t.id,
              ticketNumber: t.ticket_number || 0,
              title: t.title,
              description: t.description,
              requester: t.profiles?.name || t.requester_name,
              requesterId: t.requester_id,
              priority: t.priority,
              status: t.status,
              category: t.category,
              createdAt: new Date(t.created_at),
              updatedAt: t.updated_at ? new Date(t.updated_at) : new Date(t.created_at),
              resolvedAt: t.resolved_at ? new Date(t.resolved_at) : undefined,
              attachments: t.attachments || []
          })));
      } catch (error) {
          console.error('Error fetching tickets:', error);
      }
  };

  const handleCreateTicket = async (newTicketData: Omit<Ticket, 'id' | 'createdAt' | 'ticketNumber'>) => {
    if (!currentUser) return;
    try {
        if (ticketToEdit) {
            const { error } = await supabase.from('tickets').update({
                title: newTicketData.title,
                description: newTicketData.description,
                priority: newTicketData.priority,
                category: newTicketData.category,
                status: newTicketData.status,
                attachments: newTicketData.attachments,
                requester_id: newTicketData.requesterId, // Permite alterar o solicitante na edição também
                requester_name: newTicketData.requester
            }).eq('id', ticketToEdit.id);
            if (error) throw error;
            setTicketToEdit(null);
        } else {
            const { error } = await supabase.from('tickets').insert([{
                title: newTicketData.title,
                description: newTicketData.description,
                requester_name: newTicketData.requester, 
                requester_id: newTicketData.requesterId,
                priority: newTicketData.priority,
                category: newTicketData.category,
                status: 'OPEN',
                attachments: newTicketData.attachments
            }]);
            if (error) throw error;
        }
        await fetchTickets();
        setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS');
    } catch (error) {
        alert("Erro ao salvar chamado.");
    }
  };

  const handleUpdateStatus = async (id: string, status: TicketStatus) => {
    try {
        const { error } = await supabase.from('tickets').update({ 
            status, 
            resolved_at: status === TicketStatus.RESOLVED ? new Date().toISOString() : null 
        }).eq('id', id);
        if (error) throw error;
        await fetchTickets();
    } catch (error) {
        console.error("Error status:", error);
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (currentView) {
      case 'CREATE_TICKET':
      case 'EDIT_TICKET':
        return <TicketForm onSave={handleCreateTicket} onCancel={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} initialData={currentView === 'EDIT_TICKET' ? ticketToEdit || undefined : undefined} currentUser={currentUser} />;
      case 'TICKET_DETAIL':
        return selectedTicket ? <TicketDetail ticket={selectedTicket} currentUser={currentUser} onBack={() => setCurrentView(currentUser.role === 'USER' ? 'MY_TICKETS' : 'ALL_TICKETS')} onUpdateStatus={handleUpdateStatus} onDelete={() => {}} onEdit={(t) => {setTicketToEdit(t); setCurrentView('EDIT_TICKET');}} /> : null;
      case 'USERS':
        return <UserManagement currentUser={currentUser} />;
      case 'NOTIFICATIONS':
        return <Notifications currentUser={currentUser} onSelectNotification={() => {}} />;
      case 'MY_TICKETS':
      case 'ALL_TICKETS':
        return <TicketList tickets={tickets} onSelectTicket={(t) => { setSelectedTicket(t); setCurrentView('TICKET_DETAIL'); }} onCreateTicket={() => setCurrentView('CREATE_TICKET')} onUpdateStatus={handleUpdateStatus} />;
      default:
        return <Dashboard tickets={tickets} currentUser={currentUser} onCreateTicket={() => setCurrentView('CREATE_TICKET')} />;
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-gray-50"><Loader2 className="animate-spin text-primary-600" size={48} /></div>;
  if (!currentUser) return <Login onLoginSuccess={() => checkUser()} />;

  return (
    <div className="flex min-h-screen bg-gray-50 text-gray-900 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        currentUser={currentUser} 
        tickets={tickets} // Propriedade sincronizada
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />
      <main className="flex-1 transition-all duration-300 md:ml-64 p-4 md:p-8">
          <div className="md:hidden flex items-center justify-between mb-6 bg-white p-3 rounded-xl border border-gray-200">
              <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"><Menu /></button>
              <Logo className="h-8" />
              <div className="h-8 w-8 rounded-full bg-primary-600 text-white flex items-center justify-center text-xs font-bold">{currentUser.name.charAt(0)}</div>
          </div>
          <div className="max-w-7xl mx-auto">
             {renderContent()}
          </div>
      </main>
    </div>
  );
};

export default App;

export enum TicketStatus {
  OPEN = 'OPEN',
  IN_PROGRESS = 'IN_PROGRESS',
  RESOLVED = 'RESOLVED'
}

export enum TicketPriority {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export type UserRole = 'ADMIN' | 'USER';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
  isActive?: boolean;
}

export interface Ticket {
  id: string;
  ticketNumber: number;
  title: string;
  description: string;
  requester: string; 
  requesterId: string; 
  priority: TicketPriority;
  status: TicketStatus;
  category: string;
  createdAt: Date;
  updatedAt?: Date;
  resolvedAt?: Date;
  attachments?: string[];
}

export interface Comment {
  id: string;
  ticketId: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  content: string;
  createdAt: Date;
  source?: 'WEB' | 'EMAIL'; // Nova propriedade para rastrear origem
}

export interface Notification {
  id: string;
  userId: string;
  title: string;
  message: string;
  isRead: boolean;
  ticketId?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  ticketId: string;
  ticketNumber?: number;
  actorId: string;
  actorName?: string;
  action: string;
  details?: string;
  createdAt: Date;
}

export interface ITicketStats {
  total: number;
  open: number;
  critical: number;
  resolved: number;
}

export type ViewState = 'DASHBOARD' | 'CREATE_TICKET' | 'TICKET_DETAIL' | 'MY_TICKETS' | 'ALL_TICKETS' | 'USERS' | 'EDIT_TICKET' | 'NOTIFICATIONS';

import React, { useState, useEffect, useRef } from 'react';
import { Ticket, TicketStatus, User, Comment, AuditLog } from '../types';
import { 
  ArrowLeft, CheckCircle, Clock, User as UserIcon, Calendar, Tag, 
  Trash2, Edit, Send, MessageSquare, FileText, Paperclip, 
  Mail, ExternalLink, Info, MailCheck
} from 'lucide-react';
import { supabase } from '../services/supabase';

interface TicketDetailProps {
  ticket: Ticket;
  currentUser: User;
  onBack: () => void;
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  onDelete: (id: string) => void;
  onEdit: (ticket: Ticket) => void;
}

export const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, currentUser, onBack, onUpdateStatus, onDelete, onEdit }) => {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loadingComments, setLoadingComments] = useState(true);
  const [isSimulatingEmail, setIsSimulatingEmail] = useState(false);
  const commentsEndRef = useRef<HTMLDivElement>(null);
  const [logs, setLogs] = useState<AuditLog[]>([]);

  const isAdmin = currentUser.role === 'ADMIN';
  const isOwner = currentUser.id === ticket.requesterId;

  // Endereço de e-mail único para este ticket (Simulação de Inbound Parse)
  const ticketInboundEmail = `chamado+${ticket.ticketNumber}@airservice.com.br`;

  useEffect(() => {
      fetchComments();
      fetchLogs();

      const channel = supabase
        .channel(`comments:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'comments', filter: `ticket_id=eq.${ticket.id}` }, () => {
            fetchComments(); 
        })
        .subscribe();

      const logsChannel = supabase
        .channel(`logs:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'audit_logs', filter: `ticket_id=eq.${ticket.id}` }, () => {
            fetchLogs();
        })
        .subscribe();

      return () => {
          supabase.removeChannel(channel);
          supabase.removeChannel(logsChannel);
      }
  }, [ticket.id]);

  useEffect(() => {
      commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [comments]);

  const fetchComments = async () => {
      const { data, error } = await supabase
        .from('comments')
        .select('*, profiles(name, role)')
        .eq('ticket_id', ticket.id)
        .order('created_at', { ascending: true });

      if (error) {
          console.error("Error fetching comments", error);
      } else {
          setComments(data.map((c: any) => ({
              id: c.id,
              ticketId: c.ticket_id,
              userId: c.user_id,
              content: c.content,
              createdAt: new Date(c.created_at),
              userName: c.profiles?.name || 'Sistema Externo',
              userRole: c.profiles?.role || 'USER',
              source: c.source || 'WEB'
          })));
      }
      setLoadingComments(false);
  };

  const fetchLogs = async () => {
    const { data } = await supabase
      .from('audit_logs')
      .select('*, profiles(name)')
      .eq('ticket_id', ticket.id)
      .order('created_at', { ascending: false });

    if (data) {
        setLogs(data.map((l: any) => ({
            id: l.id,
            ticketId: l.ticket_id,
            actorId: l.actor_id,
            actorName: l.profiles?.name || 'Sistema',
            action: l.action,
            details: l.details,
            createdAt: new Date(l.created_at)
        })));
    }
  };

  const handleSendComment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newComment.trim()) return;

      const commentText = newComment;
      setNewComment(''); 

      try {
          const { error } = await supabase.from('comments').insert({
              ticket_id: ticket.id,
              user_id: currentUser.id,
              content: commentText,
              source: 'WEB'
          });

          if (error) throw error;
      } catch (error) {
          console.error("Error sending comment:", error);
          alert("Erro ao enviar mensagem");
          setNewComment(commentText); 
      }
  };

  // Função para simular o Webhook que receberia um e-mail
  const simulateEmailResponse = async () => {
      setIsSimulatingEmail(true);
      try {
          // Simulando o comportamento de um Webhook externo (SendGrid/Mailgun)
          // que extrairia o e-mail do remetente e inseriria diretamente no Supabase
          const { error } = await supabase.from('comments').insert({
              ticket_id: ticket.id,
              user_id: ticket.requesterId, // Simula que o solicitante respondeu via e-mail
              content: "Esta é uma resposta automática simulando um e-mail enviado pelo usuário. O sistema de Webhook identificou o ticket e adicionou o comentário.",
              source: 'EMAIL'
          });

          if (error) throw error;

          await supabase.from('notifications').insert({
              user_id: isAdmin ? ticket.requesterId : '66666666-6666-6666-6666-666666666666', // Simplificado
              title: 'Nova resposta via e-mail',
              message: 'Um usuário respondeu ao chamado através do e-mail corporativo.',
              ticket_id: ticket.id
          });

      } catch (error) {
          console.error("Simulation error", error);
      } finally {
          setTimeout(() => setIsSimulatingEmail(false), 800);
      }
