                        const fromEmail = comment.source === 'EMAIL';
                        return (
                            <div key={comment.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                <div className={`flex items-center space-x-2 mb-1 ${isMe ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
                                    <span className="text-[11px] font-bold text-gray-500 uppercase">{comment.userName}</span>
                                    {fromEmail && (
                                        <span className="flex items-center px-1.5 py-0.5 rounded bg-indigo-50 text-indigo-600 text-[9px] font-bold uppercase border border-indigo-100">
                                            <Mail size={10} className="mr-1" /> via e-mail
                                        </span>
                                    )}
                                    <span className="text-[10px] text-gray-400">{comment.createdAt.toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'})}</span>
                                </div>
                                <div className={`p-4 rounded-2xl max-w-[85%] text-sm leading-relaxed shadow-sm ${
                                    isMe 
                                    ? 'bg-primary-600 text-white rounded-tr-none' 
                                    : fromEmail 
                                        ? 'bg-indigo-50 border border-indigo-100 text-indigo-900 rounded-tl-none'
                                        : 'bg-gray-100 text-gray-800 rounded-tl-none'
                                }`}>
                                    {comment.content}
                                </div>
                            </div>
                        );
                    })}
                    <div ref={commentsEndRef} />
                </div>

                <div className="p-4 bg-gray-50 border-t border-gray-200">
                    <form onSubmit={handleSendComment} className="flex gap-3">
                        <input
                            type="text"
                            value={newComment}
                            onChange={(e) => setNewComment(e.target.value)}
                            placeholder="Escreva sua resposta aqui..."
                            className="flex-1 px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none text-sm transition-all"
                        />
                        <button 
                            type="submit" 
                            disabled={!newComment.trim()}
                            className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-700 disabled:opacity-50 shadow-lg shadow-primary-200"
                        >
                            <Send size={20} />
                        </button>
                    </form>
                </div>
            </div>
        </div>

        <div className="space-y-6">
            {/* Email Integration Info Card */}
            <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 rounded-xl p-6 text-white shadow-xl shadow-indigo-100">
                <div className="flex items-center space-x-2 mb-4">
                    <Mail size={20} />
                    <h3 className="font-bold text-sm uppercase tracking-wide">Responder por E-mail</h3>
                </div>
                <p className="text-xs text-indigo-100 mb-4 leading-relaxed">
                    Você pode interagir com este suporte diretamente do seu e-mail corporativo. Envie mensagens para o endereço abaixo:
                </p>
                <div className="bg-white/10 p-3 rounded-lg border border-white/20 mb-4 flex items-center justify-between group">
                    <code className="text-[11px] font-mono select-all truncate">{ticketInboundEmail}</code>
                    <button className="text-white/60 group-hover:text-white transition-colors" title="Copiar endereço">
                        <ExternalLink size={14} />
                    </button>
                </div>
                <div className="flex items-start space-x-2 text-[10px] text-indigo-200 italic">
                    <Info size={12} className="flex-shrink-0 mt-0.5" />
                    <span>O sistema identificará automaticamente o ticket # {ticket.ticketNumber} pelo assunto ou remetente.</span>
                </div>
            </div>

            {/* Status Manager (Admin only) */}
            {isAdmin && (
                <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-5">
                    <h3 className="font-bold text-gray-900 mb-4 text-xs uppercase tracking-widest">Controle de Fluxo</h3>
                    <div className="space-y-2">
                        {[TicketStatus.OPEN, TicketStatus.IN_PROGRESS, TicketStatus.RESOLVED].map((status) => (
                            <button
                                key={status}
                                onClick={() => onUpdateStatus(ticket.id, status)}
                                className={`w-full flex items-center justify-between px-4 py-2.5 rounded-lg text-xs font-semibold transition-all ${
                                    ticket.status === status 
                                    ? 'bg-primary-50 text-primary-700 border border-primary-200' 
                                    : 'text-gray-500 hover:bg-gray-50 border border-transparent'
                                }`}
                            >
                                {translateStatus(status)}
                                {ticket.status === status && <CheckCircle size={14} />}
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {/* Audit Timeline */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6">
                <h3 className="font-bold text-gray-900 mb-6 text-xs uppercase tracking-widest flex items-center">
                    <Calendar size={14} className="mr-2 text-gray-400" /> Histórico de Auditoria
                </h3>
                <div className="space-y-6">
                    {logs.map((log, i) => (
                        <div key={log.id} className="relative flex gap-4">
                            {i !== logs.length - 1 && <div className="absolute top-5 left-[7px] w-0.5 h-full bg-gray-50" />}
                            <div className="relative z-10 w-3.5 h-3.5 mt-1 rounded-full border-2 border-white bg-gray-200 shadow-sm" />
                            <div className="flex-1">
                                <p className="text-[11px] font-bold text-gray-800 leading-none mb-1">
                                    {log.action === 'CREATED' ? 'Chamado Aberto' : 
                                     log.action === 'STATUS_CHANGE' ? 'Status Alterado' : 'Edição'}
                                </p>
                                <p className="text-[10px] text-gray-400 mb-1">{log.actorName} • {log.createdAt.toLocaleDateString('pt-BR')}</p>
                                {log.details && <p className="text-[10px] text-gray-500 italic">"{log.details}"</p>}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export enum TicketStatus {
  OPEN = 'OPEN',
  IN_PROGRESS = 'IN_PROGRESS',
  RESOLVED = 'RESOLVED'
}

export enum TicketPriority {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export type UserRole = 'ADMIN' | 'USER';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
  isActive?: boolean;
}

export interface Ticket {
  id: string;
  ticketNumber: number;
  title: string;
  description: string;
  requester: string; 
  requesterId: string; 
  priority: TicketPriority;
  status: TicketStatus;
  category: string;
  createdAt: Date;
  updatedAt?: Date;
  resolvedAt?: Date;
  attachments?: string[];
}

export interface Comment {
  id: string;
  ticketId: string;
  userId: string;
  userName: string;
  userRole: UserRole;
  content: string;
  createdAt: Date;
  source?: 'WEB' | 'EMAIL'; // Identifica a origem da mensagem
}

export interface Notification {
  id: string;
  userId: string;
  title: string;
  message: string;
  isRead: boolean;
  ticketId?: string;
  createdAt: Date;
}

export interface AuditLog {
  id: string;
  ticketId: string;
  ticketNumber?: number;
  actorId: string;
  actorName?: string;
  action: string;
  details?: string;
  createdAt: Date;
}

export interface ITicketStats {
  total: number;
  open: number;
  critical: number;
  resolved: number;
}

export type ViewState = 'DASHBOARD' | 'CREATE_TICKET' | 'TICKET_DETAIL' | 'MY_TICKETS' | 'ALL_TICKETS' | 'USERS' | 'EDIT_TICKET' | 'NOTIFICATIONS';

import React, { useState, useEffect, useRef } from 'react';
import { Ticket, TicketStatus, User, Comment, AuditLog } from '../types';
import { 
  ArrowLeft, CheckCircle, Clock, User as UserIcon, Calendar, 
  Tag, Trash2, Edit, Send, MessageSquare, FileText, 
  Paperclip, Mail, Info, ExternalLink, MailCheck 
} from 'lucide-react';
import { supabase } from '../services/supabase';

interface TicketDetailProps {
  ticket: Ticket;
  currentUser: User;
  onBack: () => void;
  onUpdateStatus: (id: string, status: TicketStatus) => void;
  onDelete: (id: string) => void;
  onEdit: (ticket: Ticket) => void;
}

export const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, currentUser, onBack, onUpdateStatus, onDelete, onEdit }) => {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loadingComments, setLoadingComments] = useState(true);
  const [isSimulatingEmail, setIsSimulatingEmail] = useState(false);
  const commentsEndRef = useRef<HTMLDivElement>(null);
  const [logs, setLogs] = useState<AuditLog[]>([]);

  const isAdmin = currentUser.role === 'ADMIN';
  const isOwner = currentUser.id === ticket.requesterId;

  // Endereço de e-mail fictício baseado na configuração de SMTP (Resend)
  const supportEmail = "ti@grupoairslaid.com.br";
  const replyEmail = `chamado+${ticket.ticketNumber}@grupoairslaid.com.br`;

  useEffect(() => {
      fetchComments();
      fetchLogs();

      const channel = supabase
        .channel(`comments:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'comments', filter: `ticket_id=eq.${ticket.id}` }, () => {
            fetchComments(); 
        })
        .subscribe();

      const logsChannel = supabase
        .channel(`logs:${ticket.id}`)
        .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'audit_logs', filter: `ticket_id=eq.${ticket.id}` }, () => {
            fetchLogs();
        })
        .subscribe();

      return () => {
          supabase.removeChannel(channel);
          supabase.removeChannel(logsChannel);
      }
  }, [ticket.id]);

  useEffect(() => {
      commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [comments]);

  const fetchComments = async () => {
      const { data, error } = await supabase
        .from('comments')
        .select('*, profiles(name, role)')
        .eq('ticket_id', ticket.id)
        .order('created_at', { ascending: true });

      if (error) {
          console.error("Error fetching comments", error);
      } else {
          setComments(data.map((c: any) => ({
              id: c.id,
              ticketId: c.ticket_id,
              userId: c.user_id,
              content: c.content,
              createdAt: new Date(c.created_at),
              userName: c.profiles?.name || 'Sistema Externo',
              userRole: c.profiles?.role || 'USER',
              source: c.source || 'WEB'
          })));
      }
      setLoadingComments(false);
  };

  const fetchLogs = async () => {
    const { data } = await supabase
      .from('audit_logs')
      .select('*, profiles(name)')
      .eq('ticket_id', ticket.id)
      .order('created_at', { ascending: false });

    if (data) {
        setLogs(data.map((l: any) => ({
            id: l.id,
            ticketId: l.ticket_id,
            actorId: l.actor_id,
            actorName: l.profiles?.name || 'Sistema',
            action: l.action,
            details: l.details,
            createdAt: new Date(l.created_at)
        })));
    }
  };

  const handleSendComment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newComment.trim()) return;

      const commentText = newComment;
      setNewComment(''); 

      try {
          const { error } = await supabase.from('comments').insert({
              ticket_id: ticket.id,
              user_id: currentUser.id,
              content: commentText,
              source: 'WEB'
          });

          if (error) throw error;
      } catch (error) {
          console.error("Error sending comment:", error);
          alert("Erro ao enviar mensagem");
          setNewComment(commentText); 
      }
  };

  // Função simuladora para demonstrar a recepção de e-mail (Webhook do Resend Inbound)
  const simulateEmailResponse = async () => {
    setIsSimulatingEmail(true);
    try {
        const { error } = await supabase.from('comments').insert({
            ticket_id: ticket.id,
            user_id: ticket.requesterId, // Simula o solicitante respondendo
            content: "Olá equipe, recebi a notificação por e-mail e estou respondendo diretamente por aqui para testar a integração. O problema parece ter sido resolvido.",
            source: 'EMAIL'
        });
        if (error) throw error;

        // Notifica o admin da resposta
        const { data: admins } = await supabase.from('profiles').select('id').eq('role', 'ADMIN');
        if (admins) {
            await supabase.from('notifications').insert(
                admins.map(a => ({
                    user_id: a.id,
                    title: `Resposta via E-mail - #${ticket.ticketNumber}`,
                    message: `O solicitante respondeu via e-mail no chamado "${ticket.title}"`,
                    ticket_id: ticket.id
                }))
            );
        }
    } catch (err) {
        console.error("Simulation failed", err);
    } finally {
        setTimeout(() => setIsSimulatingEmail(false), 800);
    }
  };

  const translatePriority = (p: string) => {
    switch(p) {
        case 'LOW': return 'Baixa';
        case 'MEDIUM': return 'Média';
        case 'HIGH': return 'Alta';
        case 'CRITICAL': return 'Crítica';
        default: return p;
    }
  };

  const translateStatus = (s: string) => {
      switch(s) {
          case 'OPEN': return 'Aberto';
          case 'IN_PROGRESS': return 'Em Progresso';
          case 'RESOLVED': return 'Resolvido';
          default: return s;
      }
  };

  return (
